import { writeFileSync } from 'node:fs';
import { join } from 'node:path';
import type { RepairableFinding, ReconcilePlan, ReconcilePlanSummary } from './types.js';
import { getKdocVersion } from '../utils/version.js';

const PLAN_FILENAME = '.kdoc-reconcile-plan.json';

export function generatePlan(findings: RepairableFinding[]): ReconcilePlan {
  const summary: ReconcilePlanSummary = {
    autoFix: findings.filter((f) => f.tier === 'auto-fix').length,
    needsApproval: findings.filter((f) => f.tier === 'needs-approval').length,
    reportOnly: findings.filter((f) => f.tier === 'report-only').length,
  };

  return {
    version: getKdocVersion(),
    generatedAt: new Date().toISOString(),
    findings,
    summary,
  };
}

export function serializePlan(
  plan: ReconcilePlan,
  projectDir: string,
  opts: { json?: boolean; dryRun?: boolean },
): void {
  const planPath = join(projectDir, PLAN_FILENAME);

  if (!opts.dryRun) {
    writeFileSync(planPath, JSON.stringify(plan, null, 2) + '\n', 'utf8');
  }

  if (opts.json) {
    console.log(JSON.stringify(plan, null, 2));
  } else {
    if (opts.dryRun) {
      console.log(`[DRY RUN] Would write plan to ${PLAN_FILENAME}`);
    } else {
      console.log(`Plan written to ${PLAN_FILENAME}`);
    }
    console.log(`  auto-fix:       ${plan.summary.autoFix}`);
    console.log(`  needs-approval: ${plan.summary.needsApproval}`);
    console.log(`  report-only:    ${plan.summary.reportOnly}`);
    console.log(`  total findings: ${plan.findings.length}`);
  }
}
