import { AREA_EXPECTATIONS, type AreaExpectation } from '../commands/doctor.js';
import type { RepairableFinding } from './types.js';

export interface CollectorOptions {
  area?: string;
  package?: string;
  path?: string;
}

/**
 * Normalize and validate a --path argument.
 * Rejects paths containing '..' segments to prevent traversal.
 * Strips leading './' for consistency.
 */
function sanitizePath(raw: string): string | null {
  const normalized = raw.replace(/\\/g, '/').replace(/^\.\//, '');
  // Reject any path with traversal segments
  if (normalized.split('/').some((seg) => seg === '..')) {
    return null;
  }
  return normalized;
}

/**
 * Test whether a repo-relative filePath belongs to a named area.
 * Uses the AREA_EXPECTATIONS map (from doctor.ts) so that area names
 * are resolved to their actual directory paths — no naive string.includes.
 * Area names are case-insensitive (normalized to lowercase for lookup).
 */
function matchesAreaFilter(filePath: string, area: string, knowledgeRoot: string): boolean {
  const normalizedArea = area.toLowerCase();
  const expectation: AreaExpectation | undefined = AREA_EXPECTATIONS[normalizedArea];
  if (!expectation) return false;

  // Root-level seed/generated files (e.g. ContextPack.md, INDEX.md)
  if (expectation.file && !expectation.path) {
    return filePath === `${knowledgeRoot}/${expectation.file}` || filePath.endsWith(`/${expectation.file}`);
  }

  // Area with its own subdirectory (e.g. ADR/, TLDR/, Roadmap/)
  if (expectation.path) {
    const prefix = `${knowledgeRoot}/${expectation.path}/`;
    return filePath.startsWith(prefix) || filePath.includes(`/${expectation.path}/`);
  }

  return false;
}

/** Test whether a filePath belongs to a specific package scope. */
function matchesPackageFilter(filePath: string, packageName: string): boolean {
  return filePath.includes(`packages/${packageName}/`);
}

/** Test whether a filePath starts with (or matches) a given path prefix. */
function matchesPathFilter(filePath: string, pathPrefix: string): boolean {
  const normalized = pathPrefix.endsWith('/') ? pathPrefix : `${pathPrefix}/`;
  return filePath.startsWith(pathPrefix) || filePath.startsWith(normalized);
}

/**
 * Filter findings by scope options with intersection semantics.
 * When multiple flags are provided, ALL must match (logical AND).
 * The --path argument is sanitized to reject traversal segments.
 */
export function applyFilters(
  findings: RepairableFinding[],
  options?: CollectorOptions,
  knowledgeRoot = 'Knowledge',
): RepairableFinding[] {
  if (!options) return findings;

  const { area, package: packageName, path: rawPath } = options;

  // Sanitize --path: reject traversal
  let path: string | undefined;
  if (rawPath) {
    const sanitized = sanitizePath(rawPath);
    if (sanitized === null) {
      // Path contains traversal segments — return empty (safe default)
      return [];
    }
    path = sanitized;
  }

  const hasAnyFilter = area || packageName || path;
  if (!hasAnyFilter) return findings;

  return findings.filter((f) => {
    if (area && !matchesAreaFilter(f.filePath, area, knowledgeRoot)) return false;
    if (packageName && !matchesPackageFilter(f.filePath, packageName)) return false;
    if (path && !matchesPathFilter(f.filePath, path)) return false;
    return true;
  });
}
