import type { KdocConfig } from '../config/schema.js';
import { repairLegacyFrontmatterField, repairStatusCase, repairSupersessionStatus } from './repairs/frontmatter.js';
import { repairMissingRequired } from './repairs/missing-file.js';
import { repairStaleContextPack, repairStaleIndex } from './repairs/regenerate.js';
import { repairBrokenWikilink } from './repairs/wikilink.js';
import type { FindingCode, RepairResult, RepairTier, RepairableFinding } from './types.js';

export type RepairFn = (
  finding: RepairableFinding,
  projectDir: string,
  config: KdocConfig,
) => Promise<RepairResult> | RepairResult;

export interface RepairHandler {
  fn: RepairFn;
  tier: RepairTier;
  phase: number;
}

const REPORT_ONLY_CODES = new Set<FindingCode>([
  'INVALID_FRONTMATTER',
  'FORBIDDEN_WIKILINK',
  'ADR_NUMBERING_GAP',
  'ADR_NUMBERING_DUPLICATE',
  'ADR_MISSING_SECTION',
  'ADR_SUPERSESSION_MISSING_SUCCESSOR',
  'ADR_SUPERSESSION_ASYMMETRIC',
  'ADR_SUPERSEDES_MISSING',
  'ADR_SUPERSEDES_ASYMMETRIC',
]);

const REPAIR_HANDLERS: Partial<Record<FindingCode, RepairHandler>> = {
  LEGACY_FRONTMATTER_FIELD: {
    fn: repairLegacyFrontmatterField,
    tier: 'auto-fix',
    phase: 2,
  },
  BROKEN_WIKILINK: {
    fn: repairBrokenWikilink,
    tier: 'auto-fix',
    phase: 3,
  },
  MISSING_REQUIRED: {
    fn: repairMissingRequired,
    tier: 'needs-approval',
    phase: 4,
  },
  ADR_SUPERSESSION_STATUS: {
    fn: repairSupersessionStatus,
    tier: 'auto-fix',
    phase: 2,
  },
  STALE_CONTEXT_PACK: {
    fn: repairStaleContextPack,
    tier: 'needs-approval',
    phase: 1,
  },
  STALE_INDEX: {
    fn: repairStaleIndex,
    tier: 'needs-approval',
    phase: 1,
  },
  FRONTMATTER_STATUS_CASE: {
    fn: repairStatusCase,
    tier: 'auto-fix',
    phase: 2,
  },
};

export function getRepairHandler(code: FindingCode): RepairHandler | null {
  if (REPORT_ONLY_CODES.has(code)) {
    return null;
  }

  return REPAIR_HANDLERS[code] ?? null;
}
