import type { ParsedKnowledgeDoc } from './index.js';

function isMemoryEntry(doc: ParsedKnowledgeDoc): boolean {
  return doc.type === 'memory' || doc.path.startsWith('AgentMemory/');
}

export function filterMemoryEntries(
  target: ParsedKnowledgeDoc,
  docs: ParsedKnowledgeDoc[],
): ParsedKnowledgeDoc[] {
  const memoryDocs = docs.filter(isMemoryEntry);
  if (target.tags.length === 0) return memoryDocs;

  const targetTags = new Set(target.tags.map((tag) => tag.toLowerCase()));
  return memoryDocs.filter((doc) =>
    doc.tags.some((tag) => targetTags.has(tag.toLowerCase())),
  );
}
