import { existsSync, readdirSync, readFileSync } from 'node:fs';
import { dirname, join, relative } from 'node:path';
import { fileURLToPath } from 'node:url';
import type { KdocConfig } from '../config/schema.js';
import { AREA_EXPECTATIONS } from '../commands/doctor.js';
import { buildContextPackArtifact, buildIndexArtifact } from './artifact-builders.js';
import { hashString } from '../utils/hash.js';
import type {
  RepairableFinding,
  FindingCode,
  FindingContext,
  MissingRequiredOwnership,
} from './types.js';
import { resolveRepairTier, FINDING_TIER_ASSIGNMENTS } from './types.js';
import { normalizeStatus } from './normalization.js';
import { applyFilters, type CollectorOptions } from './scope.js';
import { classifyFile } from './file-metadata.js';

// ---- Governance engine dynamic import (follows doctor.ts:306-316 pattern) ----

async function resolveGovernanceEngine(): Promise<string> {
  const currentDir = dirname(fileURLToPath(import.meta.url));
  const candidates = [
    join(currentDir, '..', '..', '..', 'core', 'governance-engine.mjs'),
    join(currentDir, '..', '..', 'core', 'governance-engine.mjs'),
    join(currentDir, '..', 'core', 'governance-engine.mjs'),
  ];
  const enginePath = candidates.find((p) => existsSync(p));
  if (!enginePath) {
    throw new Error(
      'Unable to resolve governance-engine.mjs. Searched:\n' + candidates.join('\n'),
    );
  }
  return enginePath;
}

// ---- Violation types from governance engine ----

/**
 * Full violation shape from report-builder.mjs (7 fields).
 * The governance collector functions return only 4 fields (missing expected/actual/fix).
 */
interface GovernanceViolation {
  code: string;
  severity: 'error' | 'warning';
  path: string;
  message: string;
  expected?: string | null;
  actual?: string | null;
  fix?: string;
}

// ---- Markdown scanning ----

function listMarkdownFiles(dir: string): string[] {
  if (!existsSync(dir)) return [];
  const files: string[] = [];
  for (const entry of readdirSync(dir, { withFileTypes: true })) {
    const fullPath = join(dir, entry.name);
    if (entry.isDirectory()) {
      files.push(...listMarkdownFiles(fullPath));
    } else if (entry.isFile() && entry.name.endsWith('.md')) {
      files.push(fullPath);
    }
  }
  return files;
}

function extractFrontmatterStatus(content: string): string | null {
  const match = content.match(/^---\n([\s\S]*?)\n---\n?/);
  if (!match) return null;
  const statusMatch = match[1].match(/^status:\s*(.+)$/m);
  if (!statusMatch) return null;
  return statusMatch[1].trim().replace(/^["']|["']$/g, '');
}

// ---- Violation → RepairableFinding mapping ----

function inferContextFromViolation(v: GovernanceViolation): FindingContext {
  const code = v.code as FindingCode;

  switch (code) {
    case 'LEGACY_FRONTMATTER_FIELD': {
      // Prefer structured fields from governance engine when available
      if (v.actual && v.expected) {
        return {
          code: 'LEGACY_FRONTMATTER_FIELD',
          legacyField: v.actual,
          canonicalField: v.expected,
        };
      }
      // Regex fallback: '... uses legacy "superseded_by". Prefer "superseded-by".'
      const legacyMatch = v.message.match(/legacy "([^"]+)"/);
      const canonicalMatch = v.message.match(/Prefer "([^"]+)"/);
      return {
        code: 'LEGACY_FRONTMATTER_FIELD',
        legacyField: legacyMatch?.[1] ?? '',
        canonicalField: canonicalMatch?.[1] ?? '',
      };
    }

    case 'INVALID_FRONTMATTER':
      return {
        code: 'INVALID_FRONTMATTER',
        field: v.expected ?? '',
        expected: v.expected ?? '',
        actual: v.actual ?? '',
      };

    case 'BROKEN_WIKILINK': {
      // Prefer structured `expected` field (set by report-builder.mjs)
      const target = v.expected ?? v.message.match(/\[\[([^\]]+)\]\]/)?.[1] ?? '';
      return {
        code: 'BROKEN_WIKILINK',
        target,
        candidates: [], // populated later by findWikilinkCandidates
      };
    }

    case 'FORBIDDEN_WIKILINK':
      return { code: 'FORBIDDEN_WIKILINK' };

    case 'MISSING_REQUIRED':
      return {
        code: 'MISSING_REQUIRED',
        templateName: '',
        areaName: '',
        ownership: 'report-only',
      };

    case 'ADR_NUMBERING_GAP':
      return { code: 'ADR_NUMBERING_GAP' };

    case 'ADR_NUMBERING_DUPLICATE':
      return { code: 'ADR_NUMBERING_DUPLICATE' };

    case 'ADR_MISSING_SECTION': {
      // Prefer structured `expected` field when available
      if (v.expected) {
        return { code: 'ADR_MISSING_SECTION', section: v.expected };
      }
      const sectionMatch = v.message.match(/missing required section "## ([^"]+)"/);
      return { code: 'ADR_MISSING_SECTION', section: sectionMatch?.[1] ?? '' };
    }

    case 'ADR_SUPERSESSION_STATUS': {
      // Prefer structured fields when available
      if (v.actual) {
        return {
          code: 'ADR_SUPERSESSION_STATUS',
          expectedStatus: v.expected ?? 'superseded',
          actualStatus: v.actual,
        };
      }
      const statusMatch = v.message.match(/status is "([^"]*)"/);
      return {
        code: 'ADR_SUPERSESSION_STATUS',
        expectedStatus: 'superseded',
        actualStatus: statusMatch?.[1] ?? '',
      };
    }

    case 'ADR_SUPERSESSION_MISSING_SUCCESSOR':
      return { code: 'ADR_SUPERSESSION_MISSING_SUCCESSOR' };

    case 'ADR_SUPERSESSION_ASYMMETRIC':
      return { code: 'ADR_SUPERSESSION_ASYMMETRIC' };

    case 'ADR_SUPERSEDES_MISSING':
      return { code: 'ADR_SUPERSEDES_MISSING' };

    case 'ADR_SUPERSEDES_ASYMMETRIC':
      return { code: 'ADR_SUPERSEDES_ASYMMETRIC' };

    default:
      // Unrecognized code — treat as report-only with minimal context
      return { code: 'ADR_NUMBERING_GAP' };
  }
}

function mapViolationToFinding(v: GovernanceViolation): RepairableFinding | null {
  const code = v.code as FindingCode;

  // Skip unknown codes not in FINDING_TIER_ASSIGNMENTS
  if (!(code in FINDING_TIER_ASSIGNMENTS)) return null;

  const context = inferContextFromViolation(v);

  return {
    code,
    filePath: v.path,
    tier: resolveRepairTier(context),
    severity: v.severity,
    message: v.message,
    context,
  };
}

// ---- Wikilink candidate finding (Claude HIGH-2) ----

/**
 * For a broken wikilink target, scan Knowledge .md files for case-insensitive
 * matches (with and without .md extension). Returns matching repo-relative paths.
 */
function findWikilinkCandidates(
  target: string,
  projectDir: string,
  knowledgeRoot: string,
): string[] {
  const kDir = join(projectDir, knowledgeRoot);
  if (!existsSync(kDir)) return [];

  const allFiles = listMarkdownFiles(kDir);
  const normalizedTarget = target.toLowerCase().replace(/\.md$/, '');
  const candidates: string[] = [];

  for (const absPath of allFiles) {
    const relToKnowledge = relative(kDir, absPath);
    const relNoExt = relToKnowledge.replace(/\.md$/, '').toLowerCase();
    const filename = relToKnowledge.split('/').pop()?.replace(/\.md$/, '').toLowerCase() ?? '';

    if (relNoExt === normalizedTarget || filename === normalizedTarget) {
      candidates.push(join(knowledgeRoot, relToKnowledge));
    }
  }

  return candidates.sort();
}

// ---- Status case detection (Claude M1) ----

function detectStatusCaseViolations(
  projectDir: string,
  knowledgeRoot: string,
): RepairableFinding[] {
  const findings: RepairableFinding[] = [];
  const kDir = join(projectDir, knowledgeRoot);

  for (const absPath of listMarkdownFiles(kDir)) {
    const content = readFileSync(absPath, 'utf8');
    const status = extractFrontmatterStatus(content);
    if (!status) continue;

    const normalized = normalizeStatus(status);
    if (normalized === null) continue; // already canonical or unknown

    const relPath = relative(projectDir, absPath);
    findings.push({
      code: 'FRONTMATTER_STATUS_CASE',
      filePath: relPath,
      tier: 'auto-fix',
      severity: 'warning',
      message: `Status "${status}" should be "${normalized}" in ${relPath}`,
      context: { code: 'FRONTMATTER_STATUS_CASE', actual: status, normalized },
    });
  }

  return findings;
}

// ---- Staleness detection via content hash (Claude HIGH-4) ----

/**
 * Detect stale INDEX.md and ContextPack.md by comparing current content hash
 * against what the generate pipeline would produce.
 *
 * NOTE: This requires the artifact-builders module from A0.4. Since A0.4 may
 * not be available yet, we degrade gracefully: if the builders are not
 * importable, we skip staleness detection and log a warning.
 */
async function detectStaleness(
  projectDir: string,
  config: KdocConfig,
  warnings: string[],
): Promise<RepairableFinding[]> {
  const findings: RepairableFinding[] = [];
  const knowledgeRoot = config.root ?? 'Knowledge';

  // INDEX.md staleness
  try {
    const desired = buildIndexArtifact(projectDir, config);
    const indexPath = join(projectDir, knowledgeRoot, 'INDEX.md');
    if (existsSync(indexPath)) {
      const current = readFileSync(indexPath, 'utf8');
      if (hashString(current) !== hashString(desired.content)) {
        findings.push({
          code: 'STALE_INDEX',
          filePath: join(knowledgeRoot, 'INDEX.md'),
          tier: 'needs-approval',
          severity: 'warning',
          message: `INDEX.md content differs from what generate would produce`,
          context: { code: 'STALE_INDEX' },
        });
      }
    }
  } catch (err) {
    warnings.push(`Staleness check for INDEX.md failed: ${err instanceof Error ? err.message : String(err)}`);
  }

  // ContextPack.md staleness (root scope)
  try {
    const desired = buildContextPackArtifact(projectDir, config);
    const cpPath = join(projectDir, knowledgeRoot, 'ContextPack.md');
    if (existsSync(cpPath)) {
      const current = readFileSync(cpPath, 'utf8');
      if (hashString(current) !== hashString(desired.content)) {
        findings.push({
          code: 'STALE_CONTEXT_PACK',
          filePath: join(knowledgeRoot, 'ContextPack.md'),
          tier: 'needs-approval',
          severity: 'warning',
          message: `ContextPack.md content differs from what generate would produce`,
          context: { code: 'STALE_CONTEXT_PACK' },
        });
      }
    }
  } catch (err) {
    warnings.push(`Staleness check for ContextPack.md failed: ${err instanceof Error ? err.message : String(err)}`);
  }

  // Package-scoped ContextPacks
  if (config.topology === 'monorepo' && config.packages) {
    for (const pkgName of Object.keys(config.packages)) {
      try {
        const desired = buildContextPackArtifact(projectDir, config, pkgName);
        const cpPath = join(projectDir, knowledgeRoot, 'packages', pkgName, 'ContextPack.md');
        if (existsSync(cpPath)) {
          const current = readFileSync(cpPath, 'utf8');
          if (hashString(current) !== hashString(desired.content)) {
            findings.push({
              code: 'STALE_CONTEXT_PACK',
              filePath: join(knowledgeRoot, 'packages', pkgName, 'ContextPack.md'),
              tier: 'needs-approval',
              severity: 'warning',
              message: `ContextPack.md for ${pkgName} content differs from what generate would produce`,
              context: { code: 'STALE_CONTEXT_PACK', packageScope: pkgName },
            });
          }
        }
      } catch (err) {
        warnings.push(`Staleness check for ${pkgName}/ContextPack.md failed: ${err instanceof Error ? err.message : String(err)}`);
      }
    }
  }

  return findings;
}

// ---- MISSING_REQUIRED classification ----
// Delegated to file-metadata.ts (shared with doctor.ts)

function normalizeMissingRequiredFilePath(
  filePath: string,
  knowledgeRoot: string,
): string {
  if (filePath.startsWith(`${knowledgeRoot}/`)) {
    return filePath;
  }

  const [areaName, ...rest] = filePath.split('/');
  const expectation = AREA_EXPECTATIONS[areaName];
  if (!expectation) {
    return filePath;
  }

  const missingFile = rest.join('/');
  if (expectation.path) {
    return `${knowledgeRoot}/${expectation.path}/${missingFile}`;
  }

  return `${knowledgeRoot}/${missingFile}`;
}

// ---- Main collector ----

export interface CollectorResult {
  findings: RepairableFinding[];
  warnings: string[];
}

export async function collectFindings(
  projectDir: string,
  config: KdocConfig,
  options?: CollectorOptions,
): Promise<CollectorResult> {
  const findings: RepairableFinding[] = [];
  const warnings: string[] = [];
  const knowledgeRoot = config.root ?? 'Knowledge';

  // 1. Run governance engine (dynamic import — mandatory per Claude HIGH-1)
  const enginePath = await resolveGovernanceEngine();
  const engine = await import(enginePath);
  const report = engine.runGovernance(projectDir, {
    knowledgeRoot,
    extensionAreas: config.extensionAreas,
  });

  // 2. Map governance violations to RepairableFinding[]
  for (const v of (report.violations ?? []) as GovernanceViolation[]) {
    const finding = mapViolationToFinding(v);
    if (!finding) continue;

    // Enrich BROKEN_WIKILINK findings with candidate search
    if (finding.code === 'BROKEN_WIKILINK') {
      const ctx = finding.context as { code: 'BROKEN_WIKILINK'; target: string; candidates: string[] };
      ctx.candidates = findWikilinkCandidates(ctx.target, projectDir, knowledgeRoot);
      // Re-resolve tier now that candidates are populated (AC-14)
      finding.tier = resolveRepairTier(finding.context);
    }

    // Enrich MISSING_REQUIRED with classification (via shared file-metadata)
    if (finding.code === 'MISSING_REQUIRED') {
      finding.filePath = normalizeMissingRequiredFilePath(finding.filePath, knowledgeRoot);
      const classification = classifyFile(finding.filePath, knowledgeRoot);
      const ctx = finding.context as {
        code: 'MISSING_REQUIRED';
        templateName: string;
        areaName: string;
        ownership: MissingRequiredOwnership;
      };
      ctx.templateName = classification.templateName;
      ctx.areaName = classification.areaName;
      ctx.ownership = classification.ownership;
      // Re-resolve tier now that ownership is set
      finding.tier = resolveRepairTier(finding.context);
    }

    findings.push(finding);
  }

  // 3. Status case detection
  findings.push(...detectStatusCaseViolations(projectDir, knowledgeRoot));

  // 4. Staleness detection via content hash (warnings surfaced, not swallowed)
  findings.push(...await detectStaleness(projectDir, config, warnings));

  // 5. Apply scope filters (intersection semantics — AC-8)
  return { findings: applyFilters(findings, options, knowledgeRoot), warnings };
}
