import { AREA_EXPECTATIONS, type AreaExpectation } from '../commands/doctor.js';
import type { MissingRequiredOwnership } from './types.js';

export type FileOwnership = MissingRequiredOwnership;

export interface FileClassification {
  ownership: FileOwnership;
  templateName: string;
  areaName: string;
}

/**
 * Classify a Knowledge file by ownership type.
 *
 * Used by both the reconcile collector (for MISSING_REQUIRED enrichment) and
 * the doctor command. Single source of truth for "can this file be
 * auto-generated / templated / seeded?"
 *
 * @param filePath  Repo-relative path, e.g. `Knowledge/INDEX.md`
 * @param knowledgeRoot  Knowledge root from config, e.g. `Knowledge`
 * @param areaExpectations  Override for testing; defaults to AREA_EXPECTATIONS from doctor.ts
 */
export function classifyFile(
  filePath: string,
  knowledgeRoot: string,
  areaExpectations: Record<string, AreaExpectation> = AREA_EXPECTATIONS,
): FileClassification {
  // ---- Generated files (INDEX.md, ContextPack.md) ----

  // Root or package-scoped ContextPack.md
  if (filePath.endsWith('/ContextPack.md') || filePath === `${knowledgeRoot}/ContextPack.md`) {
    return {
      templateName: 'core/templates/contextpack.md',
      areaName: 'context-pack',
      ownership: 'generated',
    };
  }

  // Root INDEX.md
  if (filePath === `${knowledgeRoot}/INDEX.md`) {
    return {
      templateName: 'core/templates/index.md',
      areaName: 'index',
      ownership: 'generated',
    };
  }

  // ---- Area-expectation-based classification ----

  for (const [areaName, expectation] of Object.entries(areaExpectations)) {
    // Seed-file or generated-required with explicit filename
    if (expectation.file) {
      const expectedPath = expectation.path
        ? `${knowledgeRoot}/${expectation.path}/${expectation.file}`
        : `${knowledgeRoot}/${expectation.file}`;

      if (filePath === expectedPath || filePath.endsWith(expectation.file)) {
        if (expectation.type === 'generated-required') {
          return {
            templateName: `core/templates/${expectation.file.toLowerCase()}`,
            areaName,
            ownership: 'generated',
          };
        }
        if (expectation.type === 'seed-file-required') {
          return {
            templateName: `core/templates/${expectation.file.toLowerCase()}`,
            areaName,
            ownership: 'seeded',
          };
        }
      }
    }

    // README-required areas
    if (expectation.type === 'readme-required' && expectation.path) {
      const readmePath = `${knowledgeRoot}/${expectation.path}/README.md`;
      if (filePath === readmePath || filePath.endsWith(`${expectation.path}/README.md`)) {
        return {
          templateName: `core/templates/readme-${areaName}.md`,
          areaName,
          ownership: 'templated-user',
        };
      }
    }
  }

  return { templateName: '', areaName: '', ownership: 'report-only' };
}
