import type { KdocConfig } from '../config/schema.js';

export interface KnowledgeScope {
  /** 'root' for the main scope, package name for monorepo packages, category name for vault */
  name: string;
  type: 'root' | 'package' | 'category';
  /** Absolute path to this scope's Knowledge root directory */
  knowledgeRoot: string;
  /** Areas enabled for this scope (inherited from root if not overridden) */
  areas: Record<string, { enabled: boolean; scopes?: string[] }>;
}

/**
 * Resolve all Knowledge scopes from config.
 * - Single topology → just root scope
 * - Monorepo → root scope + one scope per package
 * - Vault → root scope + one scope per category
 */
export function resolveScopes(config: KdocConfig, projectRoot: string): KnowledgeScope[] {
  const root = config.root ?? 'Knowledge';
  const rootPath = `${projectRoot}/${root}`;
  const rootAreas = config.areas ?? {};

  const scopes: KnowledgeScope[] = [];

  // Root scope is always present
  scopes.push({
    name: 'root',
    type: 'root',
    knowledgeRoot: rootPath,
    areas: rootAreas,
  });

  if (config.topology === 'monorepo' && config.packages) {
    for (const [pkgName, pkgConfig] of Object.entries(config.packages)) {
      // Per R1: package docs live inside root Knowledge at Knowledge/packages/<name>/
      const pkgKnowledgeRoot = `${rootPath}/packages/${pkgName}`;
      scopes.push({
        name: pkgName,
        type: 'package',
        knowledgeRoot: pkgKnowledgeRoot,
        // Inherit root areas if package doesn't override
        areas: pkgConfig.areas ?? rootAreas,
      });
    }
  }

  if (config.topology === 'vault' && config.categories) {
    for (const [catName, catConfig] of Object.entries(config.categories)) {
      scopes.push({
        name: catName,
        type: 'category',
        knowledgeRoot: `${rootPath}/${catName}`,
        areas: {}, // Categories don't use standard areas
      });
    }
  }

  return scopes;
}

/**
 * Resolve the scope for a specific package name.
 * Returns null if the package is not configured.
 */
export function resolveScopeForPackage(
  config: KdocConfig,
  projectRoot: string,
  packageName: string,
): KnowledgeScope | null {
  if (config.topology !== 'monorepo' || !config.packages?.[packageName]) {
    return null;
  }

  const root = config.root ?? 'Knowledge';
  const rootPath = `${projectRoot}/${root}`;
  const rootAreas = config.areas ?? {};
  const pkgConfig = config.packages[packageName];

  return {
    name: packageName,
    type: 'package',
    knowledgeRoot: `${rootPath}/packages/${packageName}`,
    areas: pkgConfig.areas ?? rootAreas,
  };
}

/**
 * Resolve the root scope (shared/global).
 */
export function resolveRootScope(config: KdocConfig, projectRoot: string): KnowledgeScope {
  const root = config.root ?? 'Knowledge';
  return {
    name: 'root',
    type: 'root',
    knowledgeRoot: `${projectRoot}/${root}`,
    areas: config.areas ?? {},
  };
}
