import { readFileSync, existsSync, readdirSync } from 'node:fs';
import { join, basename } from 'node:path';
import { parseDocument } from 'yaml';
import type {
  Phase,
  SubPhase,
  PhaseStatus,
  SubPhaseStatus,
  PhaseEffort,
  PhaseHorizon,
  PhaseSource,
} from './index.js';

function parseFrontmatter(content: string): Record<string, unknown> {
  const match = content.match(/^---\n([\s\S]*?)\n---/);
  if (!match) return {};
  const doc = parseDocument(match[1]);
  if (doc.errors.length > 0) return {};
  const parsed = doc.toJSON();
  return parsed && typeof parsed === 'object' ? parsed as Record<string, unknown> : {};
}

function toStringArray(val: unknown): string[] {
  if (Array.isArray(val)) return val.map((item) => toString(item)).filter(Boolean);
  if (typeof val === 'string' && val) return [val];
  return [];
}

function toString(val: unknown): string {
  if (typeof val === 'string') return val;
  if (val instanceof Date) return val.toISOString().slice(0, 10);
  if (typeof val === 'number' || typeof val === 'boolean' || typeof val === 'bigint') {
    return String(val);
  }
  return '';
}

function toNumber(val: unknown, fallback: number): number {
  if (typeof val === 'number') return val;
  if (typeof val === 'string') {
    const n = parseInt(val, 10);
    return isNaN(n) ? fallback : n;
  }
  return fallback;
}

function toStatus(val: unknown, valid: readonly string[], fallback: string): string {
  const s = toString(val);
  return valid.includes(s) ? s : fallback;
}

function toOptionalEnum<T extends string>(val: unknown, valid: readonly T[]): T | undefined {
  const parsed = toStatus(val, valid, '');
  return parsed ? parsed as T : undefined;
}

const PHASE_STATUSES = ['pending', 'in_progress', 'completed', 'completed_with_notes', 'blocked'] as const;
const SUBPHASE_STATUSES = ['pending', 'in_progress', 'completed', 'completed_with_notes', 'blocked'] as const;
const PHASE_HORIZONS = ['now', 'next', 'later', 'backlog'] as const;
const PHASE_EFFORTS = ['S', 'M', 'L', 'XL'] as const;
const PHASE_SOURCES = ['manual', 'workshop', 'discovery', 'imported'] as const;

function parsePhaseFile(filePath: string): Omit<Phase, 'subPhases'> | null {
  if (!existsSync(filePath)) return null;
  const content = readFileSync(filePath, 'utf8');
  const fm = parseFrontmatter(content);

  if (fm['type'] !== 'phase') return null;

  return {
    id: toString(fm['id']) || basename(filePath, '.md'),
    name: toString(fm['summary']) || toString(fm['title']) || basename(filePath, '.md'),
    status: toStatus(fm['status'], PHASE_STATUSES, 'pending') as PhaseStatus,
    dependsOn: toStringArray(fm['depends_on']),
    intent: toString(fm['intent']),
    path: filePath,
    summary: toString(fm['summary']),
    workUnitsTotal: toNumber(fm['work_units_total'], 0),
    lastReviewed: toString(fm['last_reviewed']) || undefined,
    acceptanceCriteria: toStringArray(fm['acceptance_criteria']),
    horizon: toOptionalEnum(fm['horizon'], PHASE_HORIZONS) as PhaseHorizon | undefined,
    outcome: toString(fm['outcome']) || undefined,
    successMetrics: toStringArray(fm['success_metrics']),
    estimatedEffort: toOptionalEnum(fm['estimated_effort'], PHASE_EFFORTS) as PhaseEffort | undefined,
    source: toOptionalEnum(fm['source'], PHASE_SOURCES) as PhaseSource | undefined,
    sourceRef: toString(fm['source_ref']) || undefined,
    startedAt: toString(fm['started_at']) || undefined,
    completedAt: toString(fm['completed_at']) || undefined,
    workshopRefs: toStringArray(fm['workshop_refs']),
    prRefs: toStringArray(fm['pr_refs']),
  };
}

function parseSubPhaseFile(filePath: string): SubPhase | null {
  if (!existsSync(filePath)) return null;
  const content = readFileSync(filePath, 'utf8');
  const fm = parseFrontmatter(content);

  if (fm['type'] !== 'sub-phase') return null;

  return {
    id: toString(fm['id']) || basename(filePath, '.md'),
    parentPhase: toString(fm['parent_phase']),
    name: toString(fm['summary']) || toString(fm['title']) || basename(filePath, '.md'),
    status: toStatus(fm['status'], SUBPHASE_STATUSES, 'pending') as SubPhaseStatus,
    blockedBy: toStringArray(fm['blocked_by']),
    parallelWith: toStringArray(fm['parallel_with']),
    tldr: toString(fm['tldr']),
    designSpec: toString(fm['design_spec']),
    size: toString(fm['size']),
    securityTier: toString(fm['security_tier']) || 'standard',
    intent: toString(fm['intent']),
    acceptanceCriteria: toStringArray(fm['acceptance_criteria']),
    modulePath: toString(fm['module_path']),
    affectedRoutes: toStringArray(fm['affected_routes']),
    path: filePath,
    summary: toString(fm['summary']),
    app: toString(fm['app']) || undefined,
  };
}

/**
 * Parse all phases and sub-phases from a Roadmap directory.
 * Expects: Knowledge/Roadmap/phases/phase-N.md and phases/phase-N/N.X.md
 */
export function parseRoadmap(roadmapDir: string): Phase[] {
  const phasesDir = join(roadmapDir, 'phases');
  if (!existsSync(phasesDir)) return [];

  const entries = readdirSync(phasesDir, { withFileTypes: true });
  const phases: Phase[] = [];

  // Parse phase files
  for (const entry of entries) {
    if (!entry.isFile() || !entry.name.endsWith('.md')) continue;
    if (!entry.name.startsWith('phase-')) continue;

    const filePath = join(phasesDir, entry.name);
    const parsed = parsePhaseFile(filePath);
    if (!parsed) continue;

    // Find sub-phases in the matching directory
    const phaseId = parsed.id;
    const phaseNum = phaseId.replace('phase-', '');
    const subPhaseDir = join(phasesDir, `phase-${phaseNum}`);
    const subPhases: SubPhase[] = [];

    if (existsSync(subPhaseDir)) {
      const subEntries = readdirSync(subPhaseDir, { withFileTypes: true });
      for (const subEntry of subEntries) {
        if (!subEntry.isFile() || !subEntry.name.endsWith('.md')) continue;
        const subPath = join(subPhaseDir, subEntry.name);
        const subParsed = parseSubPhaseFile(subPath);
        if (subParsed) subPhases.push(subParsed);
      }
    }

    // Sort sub-phases by ID
    subPhases.sort((a, b) => {
      const aParts = a.id.split('.').map(Number);
      const bParts = b.id.split('.').map(Number);
      for (let i = 0; i < Math.max(aParts.length, bParts.length); i++) {
        const diff = (aParts[i] ?? 0) - (bParts[i] ?? 0);
        if (diff !== 0) return diff;
      }
      return 0;
    });

    phases.push({ ...parsed, subPhases });
  }

  // Sort phases by ID
  phases.sort((a, b) => {
    const aNum = parseFloat(a.id.replace('phase-', '').replace(/[a-z]/g, '.5'));
    const bNum = parseFloat(b.id.replace('phase-', '').replace(/[a-z]/g, '.5'));
    return aNum - bNum;
  });

  return phases;
}
