// cli/src/commands/doctor.ts
import { Command } from 'commander';
import { existsSync, readdirSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';
import { loadConfig } from '../config/loader.js';
import { hasPendingLockTmp } from '../config/lock.js';
import { readFileSafe } from '../utils/fs.js';
import { resolveScopes } from '../topology/scopes.js';
import { runScopedStructureChecks, runScopedStructureChecksForPackage } from '../governance/scopes.js';
import { runIntentChecks } from '../governance/intent.js';
import { getKdocVersion } from '../utils/version.js';

// ---- Types ----

export type CheckCategory = 'config' | 'structure' | 'scripts' | 'integrations' | 'governance';
export type CheckStatus = 'pass' | 'fail' | 'warn';

export interface CheckResult {
  category: CheckCategory;
  name: string;
  status: CheckStatus;
  message: string;
  fix?: string;
}

export interface DoctorReport {
  version: string;
  status: 'healthy' | 'issues' | 'broken';
  checks: CheckResult[];
  summary: { pass: number; fail: number; warn: number };
}

// ---- Per-area structure expectations ----

export type AreaExpectationType =
  | 'empty-ok'
  | 'readme-required'
  | 'generated-required'
  | 'seed-file-required'
  | 'content-expected';

export interface AreaExpectation {
  /** Directory path relative to Knowledge root (or empty string for root-level files). */
  path: string;
  type: AreaExpectationType;
  /** For generated-required and seed-file-required: the required filename. */
  file?: string;
}

export const AREA_EXPECTATIONS: Record<string, AreaExpectation> = {
  adr: { path: 'ADR', type: 'readme-required' },
  tldr: { path: 'TLDR', type: 'readme-required' },
  roadmap: { path: 'Roadmap', type: 'readme-required' },
  design: { path: 'Design', type: 'readme-required' },
  guides: { path: 'Guides', type: 'empty-ok' },
  'agent-memory': { path: 'AgentMemory', type: 'seed-file-required', file: 'MEMORY.md' },
  runbooks: { path: 'runbooks', type: 'empty-ok' },
  'threat-models': { path: 'ThreatModels', type: 'empty-ok' },
  templates: { path: 'Templates', type: 'empty-ok' },
  governance: { path: '', type: 'empty-ok' }, // scripts live in scripts/kdoc/
  'context-pack': { path: '', type: 'seed-file-required', file: 'ContextPack.md' },
  index: { path: '', type: 'generated-required', file: 'INDEX.md' },
};

function countMarkdownFilesRecursive(dir: string): number {
  let count = 0;

  for (const entry of readdirSync(dir, { withFileTypes: true })) {
    const fullPath = join(dir, entry.name);
    if (entry.isDirectory()) {
      count += countMarkdownFilesRecursive(fullPath);
      continue;
    }

    if (entry.isFile() && entry.name.endsWith('.md') && entry.name !== 'README.md') {
      count += 1;
    }
  }

  return count;
}

// ---- Check runners ----

export function runConfigChecks(projectDir: string): CheckResult[] {
  const results: CheckResult[] = [];

  // Check .kdoc.yaml exists and is valid
  const configFilePath = join(projectDir, '.kdoc.yaml');
  if (!existsSync(configFilePath)) {
    results.push({
      category: 'config',
      name: '.kdoc.yaml exists',
      status: 'fail',
      message: '.kdoc.yaml not found',
      fix: 'npx kdoc init',
    });
    return results; // Can't check further without config
  }

  try {
    loadConfig(projectDir);
    results.push({
      category: 'config',
      name: '.kdoc.yaml exists',
      status: 'pass',
      message: '.kdoc.yaml is valid',
    });
  } catch (err) {
    results.push({
      category: 'config',
      name: '.kdoc.yaml exists',
      status: 'fail',
      message: `.kdoc.yaml is invalid: ${String(err)}`,
      fix: 'Fix validation errors in .kdoc.yaml',
    });
    return results;
  }

  // Check .kdoc.lock exists
  const lockFilePath = join(projectDir, '.kdoc.lock');
  if (!existsSync(lockFilePath)) {
    results.push({
      category: 'config',
      name: '.kdoc.lock exists',
      status: 'fail',
      message: '.kdoc.lock not found',
      fix: 'Run `npx kdoc init` to create the lock file',
    });
  } else {
    results.push({
      category: 'config',
      name: '.kdoc.lock exists',
      status: 'pass',
      message: '.kdoc.lock found',
    });
  }

  // Check for interrupted install
  if (hasPendingLockTmp(projectDir)) {
    results.push({
      category: 'config',
      name: 'No interrupted install',
      status: 'warn',
      message: '.kdoc.lock.tmp found — a previous install may have been interrupted',
      fix: 'Run `npx kdoc init` to resume or `npx kdoc undo` to clean up',
    });
  } else {
    results.push({
      category: 'config',
      name: 'No interrupted install',
      status: 'pass',
      message: 'No interrupted install detected',
    });
  }

  return results;
}

export function runStructureChecks(
  projectDir: string,
  knowledgeRoot: string,
  areas: Record<string, { enabled: boolean }>,
): CheckResult[] {
  const results: CheckResult[] = [];
  const kRoot = join(projectDir, knowledgeRoot);

  for (const [areaName, areaConfig] of Object.entries(areas)) {
    if (!areaConfig.enabled) continue;

    const expectation = AREA_EXPECTATIONS[areaName];
    if (!expectation) continue;

    const areaDir = expectation.path ? join(kRoot, expectation.path) : kRoot;
    const displayPath = expectation.path || knowledgeRoot;

    // Directory existence check (applies to all area types with a path)
    if (expectation.path && !existsSync(areaDir)) {
      results.push({
        category: 'structure',
        name: `${displayPath} directory exists`,
        status: 'fail',
        message: `Directory ${displayPath} not found`,
        fix: `npx kdoc add ${areaName}`,
      });
      continue;
    }

    switch (expectation.type) {
      case 'empty-ok':
        results.push({
          category: 'structure',
          name: `${displayPath} directory exists`,
          status: 'pass',
          message: `${displayPath} is present`,
        });
        break;

      case 'readme-required': {
        const readmePath = join(areaDir, 'README.md');
        const readmeExists = existsSync(readmePath);
        results.push({
          category: 'structure',
          name: `${displayPath}/README.md exists`,
          status: readmeExists ? 'pass' : 'fail',
          message: readmeExists
            ? `${displayPath}/README.md found`
            : `${displayPath}/README.md is missing`,
          fix: readmeExists ? undefined : `npx kdoc add ${areaName}`,
        });
        // Soft nudge: warn if README exists but zero user docs
        if (readmeExists) {
          if (countMarkdownFilesRecursive(areaDir) === 0) {
            results.push({
              category: 'structure',
              name: `${displayPath} has user documents`,
              status: 'warn',
              message: `${displayPath} has README.md but no user-created documents yet`,
            });
          }
        }
        break;
      }

      case 'generated-required':
      case 'seed-file-required': {
        if (!expectation.file) break;
        const targetPath = expectation.path
          ? join(areaDir, expectation.file)
          : join(kRoot, expectation.file);
        const targetExists = existsSync(targetPath);
        // Include the directory path in the check name so callers can find it by area
        const checkLabel = expectation.path
          ? `${expectation.path}/${expectation.file} exists`
          : `${expectation.file} exists`;
        results.push({
          category: 'structure',
          name: checkLabel,
          status: targetExists ? 'pass' : 'fail',
          message: targetExists
            ? `${expectation.file} found`
            : `${expectation.file} is missing`,
          fix: targetExists ? undefined : `npx kdoc add ${areaName}`,
        });
        break;
      }
    }
  }

  return results;
}

export function runScriptChecks(projectDir: string, config: { scripts: { prefix: string } }): CheckResult[] {
  const checks: CheckResult[] = [];
  const projectScriptsDir = join(projectDir, 'scripts', config.scripts.prefix);

  // Resolve the kdoc package core/scripts/ directory as a fallback location.
  // Scripts may live in the project (scripts/kdoc/) or in the package (core/scripts/).
  const thisFile = fileURLToPath(import.meta.url);
  const cliDir = [dirname(thisFile), join(dirname(thisFile), '..'), join(dirname(thisFile), '..', '..')].find(
    (c) => existsSync(join(c, 'package.json')),
  ) ?? dirname(thisFile);
  const coreScriptsDir = join(cliDir, '..', 'core', 'scripts');

  const expectedScripts = [
    'check_sync.py',
    'check_wikilinks.py',
    'build_index.py',
    'check_adr_governance.py',
    'governance_health.py',
  ];

  for (const script of expectedScripts) {
    const projectPath = join(projectScriptsDir, script);
    const corePath = join(coreScriptsDir, script);
    const foundInProject = existsSync(projectPath);
    const foundInCore = existsSync(corePath);

    if (foundInProject) {
      checks.push({
        category: 'scripts',
        name: `script-${script}`,
        status: 'pass',
        message: `Python compatibility shim present at scripts/${config.scripts.prefix}/${script}. Doctor now uses the JS governance engine as the canonical backend.`,
      });
    } else if (foundInCore) {
      checks.push({
        category: 'scripts',
        name: `script-${script}`,
        status: 'pass',
        message: `Python compatibility shim available in kdoc package (${script}); doctor now uses the JS governance engine as the canonical backend.`,
      });
    } else {
      continue;
    }
  }

  return checks;
}

async function runGovernanceEngineChecks(
  projectDir: string,
): Promise<CheckResult[]> {
  try {
    const currentDir = dirname(fileURLToPath(import.meta.url));
    const enginePath = [
      join(currentDir, '..', '..', '..', 'core', 'governance-engine.mjs'),
      join(currentDir, '..', '..', 'core', 'governance-engine.mjs'),
      join(currentDir, '..', 'core', 'governance-engine.mjs'),
    ].find((candidate) => existsSync(candidate));
    if (!enginePath) {
      throw new Error('Unable to resolve governance-engine.mjs');
    }
    const engine = await import(enginePath);
    const report = engine.runGovernance(projectDir, { knowledgeRoot: loadConfig(projectDir)?.root ?? 'Knowledge' });

    if (!report.violations || report.violations.length === 0) {
      return [{
        category: 'governance',
        name: 'governance-engine',
        status: 'pass',
        message: 'JS governance engine checks passed',
      }];
    }

    return report.violations.map((violation: {
      code: string;
      severity: 'error' | 'warning';
      path: string;
      message: string;
      fix?: string;
    }) => ({
      category: 'governance',
      name: violation.code,
      status: violation.severity === 'error' ? 'fail' : 'warn',
      message: violation.path ? `${violation.path}: ${violation.message}` : violation.message,
      fix: violation.fix,
    }));
  } catch (error) {
    return [{
      category: 'governance',
      name: 'governance-engine',
      status: 'fail',
      message: `JS governance engine failed: ${error instanceof Error ? error.message : String(error)}`,
    }];
  }
}

export function runIntegrationChecks(projectDir: string, tools: string[]): CheckResult[] {
  const results: CheckResult[] = [];

  if (tools.includes('claude-code')) {
    const claudePath = join(projectDir, 'CLAUDE.md');
    const content = readFileSafe(claudePath) ?? '';
    const hasBlock = content.includes('<!-- kdoc:core:start -->');
    results.push({
      category: 'integrations',
      name: 'CLAUDE.md has kdoc block',
      status: hasBlock ? 'pass' : 'fail',
      message: hasBlock
        ? 'CLAUDE.md contains kdoc marker block'
        : 'CLAUDE.md is missing kdoc integration block',
      fix: hasBlock ? undefined : 'npx kdoc add-tool claude-code',
    });
  }

  if (tools.includes('codex')) {
    const agentsPath = join(projectDir, 'AGENTS.md');
    const content = readFileSafe(agentsPath) ?? '';
    const hasBlock = content.includes('<!-- kdoc:core:start -->');
    results.push({
      category: 'integrations',
      name: 'AGENTS.md has kdoc block',
      status: hasBlock ? 'pass' : 'fail',
      message: hasBlock
        ? 'AGENTS.md contains kdoc marker block'
        : 'AGENTS.md is missing kdoc integration block',
      fix: hasBlock ? undefined : 'npx kdoc add-tool codex',
    });
  }

  // Check package.json for kdoc:* scripts
  const pkgPath = join(projectDir, 'package.json');
  if (existsSync(pkgPath)) {
    const pkgContent = readFileSafe(pkgPath);
    if (pkgContent) {
      let pkg: Record<string, unknown>;
      try {
        pkg = JSON.parse(pkgContent) as Record<string, unknown>;
      } catch {
        pkg = {};
      }
      const scripts = (pkg['scripts'] ?? {}) as Record<string, string>;
      const kdocScripts = Object.keys(scripts).filter(k => k.startsWith('kdoc:'));
      results.push({
        category: 'integrations',
        name: 'package.json has kdoc:* scripts',
        status: kdocScripts.length > 0 ? 'pass' : 'warn',
        message:
          kdocScripts.length > 0
            ? `Found ${kdocScripts.length} kdoc:* script(s) in package.json`
            : 'No kdoc:* scripts found in package.json',
        fix: kdocScripts.length === 0 ? 'npx kdoc init (re-run to add scripts)' : undefined,
      });
    }
  }

  return results;
}

export function buildDoctorReport(version: string, checks: CheckResult[]): DoctorReport {
  const summary = { pass: 0, fail: 0, warn: 0 };
  for (const c of checks) {
    summary[c.status]++;
  }

  let status: DoctorReport['status'] = 'healthy';
  if (summary.fail > 0) status = 'broken';
  else if (summary.warn > 0) status = 'issues';

  return { version, status, checks, summary };
}

// ---- Commander registration ----

export function registerDoctorCommand(program: Command): void {
  const cmd = new Command('doctor');

  cmd
    .description('Check the health of your kdoc installation')
    .option('--json', 'Output results as JSON')
    .option('--package <name>', 'Validate only the specified package scope')
    .action(async (opts: { json?: boolean; package?: string }) => {
      const cwd = process.env.KDOC_PROJECT_DIR ?? process.cwd();

      // CONFIG checks first — if config is broken, skip further checks
      const configChecks = runConfigChecks(cwd);
      const configFailed = configChecks.some(c => c.status === 'fail');

      const allChecks: CheckResult[] = [...configChecks];

      if (!configFailed) {
        const config = loadConfig(cwd);
        if (config) {
          // Structure checks — scope-aware
          if (opts.package) {
            // Single package mode
            allChecks.push(...runScopedStructureChecksForPackage(config, cwd, opts.package));
          } else if (config.topology === 'monorepo' || config.topology === 'vault') {
            // Multi-scope: root + all packages/categories
            allChecks.push(...runScopedStructureChecks(config, cwd));
          } else {
            // Single topology — legacy behavior
            allChecks.push(...runStructureChecks(cwd, config.root, config.areas));
          }

          // Extension area checks
          const extensionAreas = (config as Record<string, unknown>).extensionAreas as Array<{ name: string; directory: string; required_files?: string[] }> | undefined;
          if (extensionAreas && extensionAreas.length > 0) {
            const kRoot = join(cwd, config.root);
            for (const ext of extensionAreas) {
              const extDir = join(kRoot, ext.directory);
              const extExists = existsSync(extDir);
              allChecks.push({
                category: 'structure',
                name: `extension:${ext.name} directory exists`,
                status: extExists ? 'pass' : 'warn',
                message: extExists
                  ? `Extension area "${ext.name}" at ${ext.directory}/ is present`
                  : `Extension area "${ext.name}" at ${ext.directory}/ not found`,
              });
              if (extExists && ext.required_files) {
                for (const req of ext.required_files) {
                  const reqPath = join(extDir, req);
                  const reqExists = existsSync(reqPath);
                  allChecks.push({
                    category: 'structure',
                    name: `extension:${ext.name}/${req} exists`,
                    status: reqExists ? 'pass' : 'fail',
                    message: reqExists
                      ? `Required file ${req} found in extension area "${ext.name}"`
                      : `Required file ${req} missing in extension area "${ext.name}"`,
                  });
                }
              }
            }
          }

          allChecks.push(...runIntegrationChecks(cwd, config.tools));
          allChecks.push(...runScriptChecks(cwd, config));
          allChecks.push(...await runGovernanceEngineChecks(cwd));

          // Intent checks (governance.intent-check, default true)
          const intentCheckEnabled = config.governance['intent-check'] !== false;
          if (intentCheckEnabled) {
            const scopes = resolveScopes(config, cwd);
            for (const scope of scopes) {
              if (scope.type === 'category') continue; // categories don't have standard frontmatter
              if (opts.package && scope.name !== opts.package && scope.type !== 'root') continue;
              if (existsSync(scope.knowledgeRoot)) {
                allChecks.push(...runIntentChecks({
                  knowledgeRoot: scope.knowledgeRoot,
                  scope: scope.name,
                }));
              }
            }
          }
        }
      }

      const report = buildDoctorReport(getKdocVersion(), allChecks);

      if (opts.json) {
        console.log(JSON.stringify(report, null, 2));
      } else {
        const icons: Record<CheckStatus, string> = { pass: '✓', fail: '✗', warn: '⚠' };
        for (const check of report.checks) {
          console.log(`  ${icons[check.status]} [${check.category}] ${check.name}: ${check.message}`);
          if (check.fix) console.log(`    Fix: ${check.fix}`);
        }
        console.log(`\nStatus: ${report.status} (${report.summary.pass} pass, ${report.summary.warn} warn, ${report.summary.fail} fail)`);
      }

      if (configFailed) {
        process.exitCode = 2;
        return;
      }
      if (report.summary.fail > 0) {
        process.exitCode = 1;
      }
    });

  program.addCommand(cmd);
}
