import { existsSync, readFileSync } from 'node:fs';
import { join } from 'node:path';
import { GENERATED_END, GENERATED_START, replaceGeneratedBlock } from '../../commands/generate.js';
import type { KdocConfig } from '../../config/schema.js';
import { safeWriteFile } from '../../utils/fs.js';
import type { RepairableFinding, RepairResult } from '../types.js';
import { buildContextPackArtifact, buildIndexArtifact } from '../artifact-builders.js';

function buildArtifactForFinding(
  finding: RepairableFinding,
  projectDir: string,
  config: KdocConfig,
): { outputPath: string; content: string } {
  const ctx = finding.context;

  if (ctx.code === 'STALE_CONTEXT_PACK') {
    return buildContextPackArtifact(projectDir, config, ctx.packageScope);
  }

  if (ctx.code === 'STALE_INDEX') {
    return buildIndexArtifact(projectDir, config);
  }

  throw new Error(`Unsupported regenerate finding: ${ctx.code}`);
}

function extractGeneratedBody(content: string): string | null {
  const startIndex = content.indexOf(GENERATED_START);
  const endIndex = content.indexOf(GENERATED_END);

  if (startIndex === -1 || endIndex === -1 || endIndex <= startIndex) {
    return null;
  }

  return content
    .slice(startIndex + GENERATED_START.length, endIndex)
    .trim();
}

function applyArtifactRepair(
  finding: RepairableFinding,
  projectDir: string,
  config: KdocConfig,
): RepairResult {
  const artifact = buildArtifactForFinding(finding, projectDir, config);
  const relativeOutputPath = finding.filePath;
  const targetPath = join(projectDir, relativeOutputPath);
  const artifactGeneratedBody = extractGeneratedBody(artifact.content);

  if (existsSync(targetPath)) {
    const existing = readFileSync(targetPath, 'utf8');
    const nextContent = artifactGeneratedBody === null
      ? artifact.content
      : replaceGeneratedBlock(existing, artifactGeneratedBody);

    if (existing === nextContent) {
      return {
        finding,
        status: 'skipped',
        reason: 'generated content already matches expected output',
        filesModified: [],
      };
    }

    safeWriteFile(targetPath, nextContent);
    return { finding, status: 'applied', filesModified: [relativeOutputPath] };
  }

  safeWriteFile(targetPath, artifact.content);
  return { finding, status: 'applied', filesModified: [relativeOutputPath] };
}

export function repairStaleContextPack(
  finding: RepairableFinding,
  projectDir: string,
  config: KdocConfig,
): RepairResult {
  if (finding.context.code !== 'STALE_CONTEXT_PACK') {
    return { finding, status: 'skipped', reason: 'Wrong context type', filesModified: [] };
  }

  return applyArtifactRepair(finding, projectDir, config);
}

export function repairStaleIndex(
  finding: RepairableFinding,
  projectDir: string,
  config: KdocConfig,
): RepairResult {
  if (finding.context.code !== 'STALE_INDEX') {
    return { finding, status: 'skipped', reason: 'Wrong context type', filesModified: [] };
  }

  return applyArtifactRepair(finding, projectDir, config);
}
