import { existsSync, readdirSync } from 'node:fs';
import { join } from 'node:path';
import type { KdocConfig } from '../config/schema.js';
import type { KnowledgeScope } from '../topology/scopes.js';
import { resolveScopes, resolveScopeForPackage } from '../topology/scopes.js';
import type { CheckResult } from '../commands/doctor.js';
import { runStructureChecks, AREA_EXPECTATIONS } from '../commands/doctor.js';

/**
 * Run structure checks for all scopes based on topology.
 * Returns results with scope labels.
 */
export function runScopedStructureChecks(
  config: KdocConfig,
  projectDir: string,
): CheckResult[] {
  const results: CheckResult[] = [];
  const scopes = resolveScopes(config, projectDir);

  for (const scope of scopes) {
    if (scope.type === 'root') {
      // Root scope: normal structure checks
      const rootChecks = runStructureChecks(projectDir, config.root, scope.areas);
      for (const check of rootChecks) {
        results.push({
          ...check,
          name: `[root] ${check.name}`,
        });
      }
    } else if (scope.type === 'package') {
      // Package scope: check Knowledge/packages/<name>/ structure
      if (!existsSync(scope.knowledgeRoot)) {
        results.push({
          category: 'structure',
          name: `[${scope.name}] Knowledge directory exists`,
          status: 'warn',
          message: `Package Knowledge directory not found: ${scope.knowledgeRoot}`,
          fix: `npx kdoc init (re-run to scaffold package directories)`,
        });
        continue;
      }

      // Check area subdirectories within the package scope
      for (const [areaName, areaConfig] of Object.entries(scope.areas)) {
        if (!areaConfig.enabled) continue;
        const areaDir = getAreaDir(areaName);
        if (!areaDir) continue;

        const fullPath = join(scope.knowledgeRoot, areaDir);
        if (!existsSync(fullPath)) {
          results.push({
            category: 'structure',
            name: `[${scope.name}] ${areaDir} directory exists`,
            status: 'warn',
            message: `Package ${scope.name}: ${areaDir}/ not found`,
          });
          continue;
        }

        results.push({
          category: 'structure',
          name: `[${scope.name}] ${areaDir} directory exists`,
          status: 'pass',
          message: `Package ${scope.name}: ${areaDir}/ found`,
        });

        const expectation = AREA_EXPECTATIONS[areaName];
        if (!expectation) continue;

        if (expectation.type === 'readme-required') {
          const readmePath = join(fullPath, 'README.md');
          const readmeExists = existsSync(readmePath);
          results.push({
            category: 'structure',
            name: `[${scope.name}] ${areaDir}/README.md exists`,
            status: readmeExists ? 'pass' : 'warn',
            message: readmeExists
              ? `Package ${scope.name}: ${areaDir}/README.md found`
              : `Package ${scope.name}: ${areaDir}/README.md is missing`,
          });
        }

        if (expectation.type === 'seed-file-required' && expectation.file) {
          const seedPath = join(fullPath, expectation.file);
          const seedExists = existsSync(seedPath);
          results.push({
            category: 'structure',
            name: `[${scope.name}] ${areaDir}/${expectation.file} exists`,
            status: seedExists ? 'pass' : 'warn',
            message: seedExists
              ? `Package ${scope.name}: ${expectation.file} found`
              : `Package ${scope.name}: ${expectation.file} is missing`,
          });
        }
      }
    } else if (scope.type === 'category') {
      // Vault category: just check directory exists
      if (!existsSync(scope.knowledgeRoot)) {
        results.push({
          category: 'structure',
          name: `[${scope.name}] category directory exists`,
          status: 'warn',
          message: `Category directory not found: ${scope.name}/`,
          fix: `Create the directory manually or re-run kdoc init`,
        });
      } else {
        results.push({
          category: 'structure',
          name: `[${scope.name}] category directory exists`,
          status: 'pass',
          message: `Category ${scope.name}/ found`,
        });
        // Check for README
        const readmePath = join(scope.knowledgeRoot, 'README.md');
        if (!existsSync(readmePath)) {
          results.push({
            category: 'structure',
            name: `[${scope.name}] README.md exists`,
            status: 'warn',
            message: `Category ${scope.name}/ is missing README.md`,
          });
        }
      }
    }
  }

  return results;
}

/**
 * Run scoped structure checks for a single package.
 */
export function runScopedStructureChecksForPackage(
  config: KdocConfig,
  projectDir: string,
  packageName: string,
): CheckResult[] {
  const scope = resolveScopeForPackage(config, projectDir, packageName);
  if (!scope) {
    return [{
      category: 'structure',
      name: `[${packageName}] package configured`,
      status: 'fail',
      message: `Package "${packageName}" is not configured in .kdoc.yaml`,
    }];
  }

  const results: CheckResult[] = [];

  if (!existsSync(scope.knowledgeRoot)) {
    results.push({
      category: 'structure',
      name: `[${packageName}] Knowledge directory exists`,
      status: 'warn',
      message: `Package Knowledge directory not found: ${scope.knowledgeRoot}`,
    });
    return results;
  }

  for (const [areaName, areaConfig] of Object.entries(scope.areas)) {
    if (!areaConfig.enabled) continue;
    const areaDir = getAreaDir(areaName);
    if (!areaDir) continue;

    const fullPath = join(scope.knowledgeRoot, areaDir);
    if (!existsSync(fullPath)) {
      results.push({
        category: 'structure',
        name: `[${packageName}] ${areaDir} directory exists`,
        status: 'warn',
        message: `Package ${packageName}: ${areaDir}/ not found`,
      });
      continue;
    }

    results.push({
      category: 'structure',
      name: `[${packageName}] ${areaDir} directory exists`,
      status: 'pass',
      message: `Package ${packageName}: ${areaDir}/ found`,
    });

    // Deeper checks matching root-scope depth
    const expectation = AREA_EXPECTATIONS[areaName];
    if (!expectation) continue;

    if (expectation.type === 'readme-required') {
      const readmePath = join(fullPath, 'README.md');
      const readmeExists = existsSync(readmePath);
      results.push({
        category: 'structure',
        name: `[${packageName}] ${areaDir}/README.md exists`,
        status: readmeExists ? 'pass' : 'warn',
        message: readmeExists
          ? `Package ${packageName}: ${areaDir}/README.md found`
          : `Package ${packageName}: ${areaDir}/README.md is missing`,
      });
    }

    if (expectation.type === 'seed-file-required' && expectation.file) {
      const seedPath = join(fullPath, expectation.file);
      const seedExists = existsSync(seedPath);
      results.push({
        category: 'structure',
        name: `[${packageName}] ${areaDir}/${expectation.file} exists`,
        status: seedExists ? 'pass' : 'warn',
        message: seedExists
          ? `Package ${packageName}: ${expectation.file} found`
          : `Package ${packageName}: ${expectation.file} is missing`,
      });
    }
  }

  return results;
}

function getAreaDir(areaName: string): string | null {
  const MAP: Record<string, string> = {
    'adr': 'ADR',
    'tldr': 'TLDR',
    'roadmap': 'Roadmap',
    'design': 'Design',
    'guides': 'Guides',
    'agent-memory': 'AgentMemory',
    'runbooks': 'runbooks',
    'threat-models': 'ThreatModels',
    'templates': 'Templates',
    'governance': 'governance',
  };
  // context-pack and index are root-level files, not directories — skip for directory checks
  return MAP[areaName] ?? null;
}
