import { existsSync, readFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const cliRoot = [join(__dirname, '..'), join(__dirname, '..', '..')].find((candidate) =>
  existsSync(join(candidate, 'package.json')),
) ?? join(__dirname, '..', '..');
const kdocRoot = join(cliRoot, '..');
const coreTemplatesDir = join(kdocRoot, 'core', 'templates');
const packsDir = join(kdocRoot, 'packs');

const CREATE_TEMPLATE_MAP: Record<string, string> = {
  adr: 'adr.md',
  tldr: 'tldr.md',
  phase: 'phase.md',
  'sub-phase': 'sub-phase.md',
  guide: 'guide.md',
  'threat-model': 'threat-model.md',
  runbook: 'runbook.md',
  'test-map': 'test-map.md',
};

export interface ResolvedTemplate {
  sourcePath: string;
  content: string;
}

function resolveCoreTemplatePath(name: string): string {
  const fileName = name.endsWith('.md') ? name : (CREATE_TEMPLATE_MAP[name] ?? `${name}.md`);
  return join(coreTemplatesDir, fileName);
}

export function loadTemplate(type: string): string {
  const filePath = resolveCoreTemplatePath(type);
  if (!existsSync(filePath)) {
    throw new Error(`Template not found for type "${type}": ${filePath}`);
  }
  return readFileSync(filePath, 'utf8');
}

export function resolveTemplateSource(templateName: string): ResolvedTemplate | null {
  if (templateName.startsWith('core/templates/')) {
    const relFile = templateName.slice('core/templates/'.length);
    const filePath = join(coreTemplatesDir, relFile);
    if (!existsSync(filePath)) return null;
    return { sourcePath: filePath, content: readFileSync(filePath, 'utf8') };
  }

  const packsMatch = templateName.match(/^packs\/([^/]+)\/templates\/(.+)$/);
  if (!packsMatch) return null;

  const [, packName, relFile] = packsMatch;
  const filePath = join(packsDir, packName, 'templates', relFile);
  if (!existsSync(filePath)) return null;
  return { sourcePath: filePath, content: readFileSync(filePath, 'utf8') };
}

export function createTemplateResolver(syntheticTemplates: Record<string, string>) {
  return (templateName: string): ResolvedTemplate | null => {
    if (templateName in syntheticTemplates) {
      return { sourcePath: templateName, content: syntheticTemplates[templateName] };
    }
    return resolveTemplateSource(templateName);
  };
}

export interface DesignPaths {
  baseDirectory: string;
  scopeAxis: string;
  specs: string;
  tokens: string;
  standards: string;
  templates: string[];
}

const DEFAULT_DESIGN_PATHS: DesignPaths = {
  baseDirectory: 'Design',
  scopeAxis: 'outer',
  specs: 'Design',
  tokens: 'Design/tokens',
  standards: 'Design/standards',
  templates: ['flow-spec.md'],
};

/**
 * Load design paths from a pack's configuration.
 * Falls back to defaults when pack has no design_paths.
 */
export function loadPackDesignPaths(packName: string): DesignPaths {
  try {
    const packPath = join(packsDir, packName, 'pack.json');
    if (!existsSync(packPath)) return DEFAULT_DESIGN_PATHS;

    const pack = JSON.parse(readFileSync(packPath, 'utf8'));
    const designPaths = pack?.areas?.design?.design_paths;
    if (!designPaths) return DEFAULT_DESIGN_PATHS;

    return {
      baseDirectory: designPaths.baseDirectory ?? DEFAULT_DESIGN_PATHS.baseDirectory,
      scopeAxis: designPaths.scopeAxis ?? DEFAULT_DESIGN_PATHS.scopeAxis,
      specs: designPaths.specs ?? DEFAULT_DESIGN_PATHS.specs,
      tokens: designPaths.tokens ?? DEFAULT_DESIGN_PATHS.tokens,
      standards: designPaths.standards ?? DEFAULT_DESIGN_PATHS.standards,
      templates: designPaths.templates ?? DEFAULT_DESIGN_PATHS.templates,
    };
  } catch {
    return DEFAULT_DESIGN_PATHS;
  }
}
