import { readFileSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';
import type { KdocConfig } from '../../config/schema.js';
import type { RepairableFinding, RepairResult } from '../types.js';

/**
 * Replace a scalar YAML field value in frontmatter.
 * Only touches the specific field line — preserves all other content including
 * multiline YAML values, comments, and body text.
 *
 * Returns the modified content, or null if the field was not found.
 */
export function replaceFrontmatterField(
  content: string,
  field: string,
  oldValue: string,
  newValue: string,
): string | null {
  const fmMatch = content.match(/^(---\n)([\s\S]*?\n)(---\n?)/);
  if (!fmMatch) return null;

  const [fullMatch, opening, body, closing] = fmMatch;
  const escapedField = escapeForRegex(field);
  const escapedOld = escapeForRegex(oldValue);

  // Match field: value with optional YAML quoting (unquoted, "double", or 'single')
  const fieldPattern = new RegExp(
    `^(${escapedField}:\\s*)(?:` +
      `${escapedOld}` +               // unquoted
      `|"${escapedOld}"` +             // double-quoted
      `|'${escapedOld}'` +             // single-quoted
    `)(\\s*)$`,
    'm',
  );

  const match = body.match(fieldPattern);
  if (!match) return null;

  // Preserve the original quoting style in the replacement
  const matchedValue = match[0].slice(match[1].length).trimEnd();
  let replacement: string;
  if (matchedValue.startsWith('"') && matchedValue.endsWith('"')) {
    replacement = `"${newValue}"`;
  } else if (matchedValue.startsWith("'") && matchedValue.endsWith("'")) {
    replacement = `'${newValue}'`;
  } else {
    replacement = newValue;
  }

  const newBody = body.replace(fieldPattern, `$1${replacement}$2`);
  return content.replace(fullMatch, `${opening}${newBody}${closing}`);
}

/**
 * Rename a frontmatter field key (e.g. superseded_by → superseded-by).
 * Preserves the field value and surrounding whitespace.
 */
function renameFrontmatterField(
  content: string,
  oldField: string,
  newField: string,
): string | null {
  const fmMatch = content.match(/^(---\n)([\s\S]*?\n)(---\n?)/);
  if (!fmMatch) return null;

  const [fullMatch, opening, body, closing] = fmMatch;

  const fieldPattern = new RegExp(
    `^${escapeForRegex(oldField)}(:\\s*)`,
    'm',
  );

  if (!fieldPattern.test(body)) return null;

  const newBody = body.replace(fieldPattern, `${newField}$1`);
  return content.replace(fullMatch, `${opening}${newBody}${closing}`);
}

/** Escape special regex characters in a string. */
function escapeForRegex(s: string): string {
  return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

// ---- Repair handlers ----

/**
 * Rename legacy underscore-style frontmatter fields to canonical kebab-case.
 * e.g. superseded_by → superseded-by, security_tier → security-tier
 */
export function repairLegacyFrontmatterField(
  finding: RepairableFinding,
  projectDir: string,
  _config: KdocConfig,
): RepairResult {
  const ctx = finding.context;
  if (ctx.code !== 'LEGACY_FRONTMATTER_FIELD') {
    return { finding, status: 'skipped', reason: 'Wrong context type', filesModified: [] };
  }

  const absPath = join(projectDir, finding.filePath);
  let content: string;
  try {
    content = readFileSync(absPath, 'utf8');
  } catch {
    return { finding, status: 'failed', reason: `Cannot read ${finding.filePath}`, filesModified: [] };
  }

  const result = renameFrontmatterField(content, ctx.legacyField, ctx.canonicalField);
  if (result === null) {
    return { finding, status: 'skipped', reason: `Field "${ctx.legacyField}" not found in frontmatter`, filesModified: [] };
  }

  writeFileSync(absPath, result, 'utf8');
  return { finding, status: 'applied', filesModified: [finding.filePath] };
}

/**
 * Normalize frontmatter status field casing.
 * e.g. status: Draft → status: draft
 */
export function repairStatusCase(
  finding: RepairableFinding,
  projectDir: string,
  _config: KdocConfig,
): RepairResult {
  const ctx = finding.context;
  if (ctx.code !== 'FRONTMATTER_STATUS_CASE') {
    return { finding, status: 'skipped', reason: 'Wrong context type', filesModified: [] };
  }

  const absPath = join(projectDir, finding.filePath);
  let content: string;
  try {
    content = readFileSync(absPath, 'utf8');
  } catch {
    return { finding, status: 'failed', reason: `Cannot read ${finding.filePath}`, filesModified: [] };
  }

  const result = replaceFrontmatterField(content, 'status', ctx.actual, ctx.normalized);
  if (result === null) {
    return { finding, status: 'skipped', reason: `status: "${ctx.actual}" not found in frontmatter`, filesModified: [] };
  }

  writeFileSync(absPath, result, 'utf8');
  return { finding, status: 'applied', filesModified: [finding.filePath] };
}

/**
 * Set status to 'superseded' when superseded-by field is present but status is wrong.
 */
export function repairSupersessionStatus(
  finding: RepairableFinding,
  projectDir: string,
  _config: KdocConfig,
): RepairResult {
  const ctx = finding.context;
  if (ctx.code !== 'ADR_SUPERSESSION_STATUS') {
    return { finding, status: 'skipped', reason: 'Wrong context type', filesModified: [] };
  }

  const absPath = join(projectDir, finding.filePath);
  let content: string;
  try {
    content = readFileSync(absPath, 'utf8');
  } catch {
    return { finding, status: 'failed', reason: `Cannot read ${finding.filePath}`, filesModified: [] };
  }

  // If actualStatus is empty/missing, the field might not exist at all
  if (ctx.actualStatus) {
    const result = replaceFrontmatterField(content, 'status', ctx.actualStatus, ctx.expectedStatus);
    if (result === null) {
      return { finding, status: 'skipped', reason: `status: "${ctx.actualStatus}" not found in frontmatter`, filesModified: [] };
    }
    writeFileSync(absPath, result, 'utf8');
  } else {
    // Status field is missing — insert it after the opening ---
    const fmMatch = content.match(/^(---\n)/);
    if (!fmMatch) {
      return { finding, status: 'skipped', reason: 'No frontmatter found', filesModified: [] };
    }
    const updated = content.replace(/^(---\n)/, `$1status: ${ctx.expectedStatus}\n`);
    writeFileSync(absPath, updated, 'utf8');
  }

  return { finding, status: 'applied', filesModified: [finding.filePath] };
}
