import type { Phase, SubPhase, DependencyGraph, Wave } from './index.js';

/**
 * Build a dependency graph from phases and their sub-phases.
 * Edges derived from depends_on (phases) and blocked_by (sub-phases).
 * Returns graph with topological ordering or throws on cycle detection.
 */
export function buildDependencyGraph(phases: Phase[]): DependencyGraph {
  const nodes = new Map<string, Phase | SubPhase>();
  const edges = new Map<string, string[]>(); // node -> nodes it depends on
  const reverseEdges = new Map<string, string[]>(); // node -> nodes that depend on it

  // Register all nodes
  for (const phase of phases) {
    nodes.set(phase.id, phase);
    edges.set(phase.id, []);
    reverseEdges.set(phase.id, []);

    for (const sub of phase.subPhases) {
      nodes.set(sub.id, sub);
      edges.set(sub.id, []);
      reverseEdges.set(sub.id, []);
    }
  }

  // Build edges from depends_on (phases)
  for (const phase of phases) {
    for (const dep of phase.dependsOn) {
      if (nodes.has(dep)) {
        edges.get(phase.id)!.push(dep);
        reverseEdges.get(dep)!.push(phase.id);
      }
    }
  }

  // Build edges from blocked_by (sub-phases)
  for (const phase of phases) {
    for (const sub of phase.subPhases) {
      for (const blocker of sub.blockedBy) {
        // Normalize: blocker might be "Phase 0b" or "1.1" or "phase-1"
        const normalized = normalizeBlocker(blocker, nodes);
        if (normalized && nodes.has(normalized)) {
          edges.get(sub.id)!.push(normalized);
          reverseEdges.get(normalized)!.push(sub.id);
        }
      }
    }
  }

  // Topological sort using Kahn's Algorithm
  const order = topologicalSort(nodes, edges);

  return { nodes, edges, reverseEdges, order };
}

function normalizeBlocker(blocker: string, nodes: Map<string, Phase | SubPhase>): string | null {
  // Direct match
  if (nodes.has(blocker)) return blocker;

  // "Phase 0b" → "phase-0b"
  const phaseMatch = blocker.match(/^Phase\s+(.+)$/i);
  if (phaseMatch) {
    const normalized = `phase-${phaseMatch[1].toLowerCase()}`;
    if (nodes.has(normalized)) return normalized;
  }

  // Try as sub-phase ID
  const trimmed = blocker.trim();
  if (nodes.has(trimmed)) return trimmed;

  return null;
}

function topologicalSort(
  nodes: Map<string, Phase | SubPhase>,
  edges: Map<string, string[]>,
): string[] {
  // Compute dependency count per node.
  // edges.get(nodeId) = list of nodes that nodeId depends on.
  // A node with 0 dependencies is ready to start (no prerequisites).
  const inDegree = new Map<string, number>();
  for (const [nodeId, deps] of edges) {
    inDegree.set(nodeId, deps.filter(d => nodes.has(d)).length);
  }
  // Ensure all nodes are in the map (some may have no edges entry)
  for (const id of nodes.keys()) {
    if (!inDegree.has(id)) inDegree.set(id, 0);
  }

  // Start with nodes that have in-degree 0 (no dependencies)
  const queue: string[] = [];
  for (const [id, degree] of inDegree) {
    if (degree === 0) queue.push(id);
  }

  const order: string[] = [];
  const visited = new Set<string>();

  while (queue.length > 0) {
    // Sort queue for deterministic output
    queue.sort();
    const current = queue.shift()!;

    if (visited.has(current)) continue;
    visited.add(current);
    order.push(current);

    // For each node that depends on current, decrement in-degree
    for (const [nodeId, deps] of edges) {
      if (visited.has(nodeId)) continue;
      if (deps.includes(current)) {
        const newDegree = (inDegree.get(nodeId) ?? 0) - 1;
        inDegree.set(nodeId, newDegree);
        if (newDegree <= 0 && !visited.has(nodeId)) {
          queue.push(nodeId);
        }
      }
    }
  }

  // Cycle detection: if we didn't visit all nodes, there's a cycle
  if (order.length < nodes.size) {
    const unvisited = [...nodes.keys()].filter(id => !visited.has(id));
    throw new Error(`Cycle detected in dependency graph. Involved nodes: ${unvisited.join(', ')}`);
  }

  return order;
}

/**
 * Group nodes into execution waves. Each wave contains nodes
 * whose dependencies are all in prior waves.
 */
export function getExecutionWaves(graph: DependencyGraph): Wave[] {
  const waves: Wave[] = [];
  const assigned = new Set<string>();
  const { nodes, edges } = graph;

  let waveNum = 1;
  while (assigned.size < nodes.size) {
    const currentWave: string[] = [];

    for (const id of nodes.keys()) {
      if (assigned.has(id)) continue;

      // Check if all dependencies are assigned (in prior waves)
      const deps = edges.get(id) ?? [];
      const allDepsResolved = deps.every(d => !nodes.has(d) || assigned.has(d));

      if (allDepsResolved) {
        currentWave.push(id);
      }
    }

    if (currentWave.length === 0) break; // Safety: prevent infinite loop

    currentWave.sort();
    waves.push({ number: waveNum, items: currentWave });
    for (const id of currentWave) assigned.add(id);
    waveNum++;
  }

  return waves;
}

/**
 * Find the critical path (longest dependency chain) through the graph.
 * Returns node IDs in order from start to end.
 */
export function getCriticalPath(graph: DependencyGraph): string[] {
  const { nodes, edges, order } = graph;

  // Distance from any start node, using topological order
  const dist = new Map<string, number>();
  const prev = new Map<string, string | null>();

  for (const id of nodes.keys()) {
    dist.set(id, 0);
    prev.set(id, null);
  }

  // Process in topological order
  for (const id of order) {
    const currentDist = dist.get(id) ?? 0;
    // For each node that depends on this one (reverse edges)
    for (const [nodeId, deps] of edges) {
      if (deps.includes(id)) {
        const newDist = currentDist + 1;
        if (newDist > (dist.get(nodeId) ?? 0)) {
          dist.set(nodeId, newDist);
          prev.set(nodeId, id);
        }
      }
    }
  }

  // Find the node with maximum distance
  let maxDist = 0;
  let endNode = '';
  for (const [id, d] of dist) {
    if (d >= maxDist) {
      maxDist = d;
      endNode = id;
    }
  }

  if (!endNode) return [];

  // Trace back the path
  const path: string[] = [];
  let current: string | null = endNode;
  while (current) {
    path.unshift(current);
    current = prev.get(current) ?? null;
  }

  return path;
}
