import type { Phase } from './index.js';
import type { NextResult } from './next.js';
import { buildDependencyGraph } from './graph.js';
import { getNextUnblocked } from './next.js';
import { parseRoadmap } from './parser.js';

export interface RoadmapStatusSnapshot {
  phases: Phase[];
  currentPhase: Phase | null;
  next: NextResult | null;
}

export function resolveRoadmapStatus(roadmapDir: string): RoadmapStatusSnapshot {
  const phases = parseRoadmap(roadmapDir);
  if (phases.length === 0) {
    return {
      phases,
      currentPhase: null,
      next: null,
    };
  }

  return {
    phases,
    currentPhase:
      phases.find((phase) => !['completed', 'completed_with_notes'].includes(phase.status)) ?? null,
    next: resolveNextUnblocked(roadmapDir)[0] ?? null,
  };
}

export function resolveNextUnblocked(roadmapDir: string): NextResult[] {
  const phases = parseRoadmap(roadmapDir);
  if (phases.length === 0) return [];
  const graph = buildDependencyGraph(phases);
  return getNextUnblocked(phases, graph);
}
