/**
 * Reconcile service layer — shared entry point for CLI and MCP.
 *
 * All reconcile operations route through here to prevent divergence
 * between CLI and MCP behavior, including event emission, convergence
 * checking, and summary formatting.
 */

import type { KdocConfig } from '../config/schema.js';
import type {
  RepairableFinding,
  RepairResult,
  RepairTier,
  ReconcilePlan,
  FindingCode,
} from './types.js';
import { collectFindings } from './collector.js';
import { executeRepairs, type ExecuteRepairsOptions } from './executor.js';
import { writeFileSync } from 'node:fs';
import { join } from 'node:path';
import { generatePlan } from './plan.js';
import type { CollectorOptions } from './scope.js';
// Event emission removed — wrapper event pipeline no longer used

// ---- Public types ----

export interface ReconcileScope {
  area?: string;
  package?: string;
  path?: string;
}

export interface CheckResult {
  findings: RepairableFinding[];
  warnings: string[];
  plan: ReconcilePlan;
}

export interface FixResult {
  findings: RepairableFinding[];
  warnings: string[];
  results: RepairResult[];
  deferredCount: number;
  clean: boolean;
}

export interface PlanResult {
  findings: RepairableFinding[];
  plan: ReconcilePlan;
  planPath?: string;
}

// ---- Helpers ----

function countByTier(findings: RepairableFinding[]): Record<string, number> {
  const counts: Record<string, number> = { auto_fix: 0, needs_approval: 0, report_only: 0 };
  for (const f of findings) {
    const key = f.tier.replace('-', '_');
    counts[key] = (counts[key] ?? 0) + 1;
  }
  return counts;
}

function countByCode(findings: RepairableFinding[]): Record<string, number> {
  const counts: Record<string, number> = {};
  for (const f of findings) {
    counts[f.code] = (counts[f.code] ?? 0) + 1;
  }
  return counts;
}

function toCollectorOptions(scope?: ReconcileScope): CollectorOptions | undefined {
  if (!scope) return undefined;
  return { area: scope.area, package: scope.package, path: scope.path };
}

// ---- Service functions ----

export async function runReconcileCheck(
  projectDir: string,
  config: KdocConfig,
  scope?: ReconcileScope,
): Promise<CheckResult> {
  const { findings, warnings } = await collectFindings(projectDir, config, toCollectorOptions(scope));
  const plan = generatePlan(findings);
  return { findings, warnings, plan };
}

export async function runReconcileFix(
  projectDir: string,
  config: KdocConfig,
  scope?: ReconcileScope,
  options?: { approve?: boolean; dryRun?: boolean },
): Promise<FixResult> {
  const { findings, warnings } = await collectFindings(projectDir, config, toCollectorOptions(scope));

  const execOptions: ExecuteRepairsOptions = {
    approve: options?.approve,
    dryRun: options?.dryRun,
  };
  const results = await executeRepairs(findings, projectDir, config, execOptions);

  // Post-fix convergence check — skip in dry-run (no files modified)
  let clean = false;
  if (!options?.dryRun) {
    const { findings: remaining } = await collectFindings(projectDir, config, toCollectorOptions(scope));
    clean = remaining.length === 0;
  }

  const deferredCount = results.filter((r) => r.status === 'skipped' && r.reason !== 'dry-run').length;
  return { findings, warnings, results, deferredCount, clean };
}

export async function runReconcilePlan(
  projectDir: string,
  config: KdocConfig,
  scope?: ReconcileScope,
  outputPath?: string,
): Promise<PlanResult> {
  const { findings } = await collectFindings(projectDir, config, toCollectorOptions(scope));
  const plan = generatePlan(findings);

  // Only write file when outputPath is provided (CLI only).
  // MCP calls without outputPath for side-effect-free operation.
  if (outputPath) {
    const resolvedPath = join(projectDir, outputPath);
    writeFileSync(resolvedPath, JSON.stringify(plan, null, 2) + '\n', 'utf8');
    return { findings, plan, planPath: outputPath };
  }

  return { findings, plan };
}
