export type FindingCode =
  | 'LEGACY_FRONTMATTER_FIELD'
  | 'INVALID_FRONTMATTER'
  | 'BROKEN_WIKILINK'
  | 'FORBIDDEN_WIKILINK'
  | 'MISSING_REQUIRED'
  | 'ADR_NUMBERING_GAP'
  | 'ADR_NUMBERING_DUPLICATE'
  | 'ADR_MISSING_SECTION'
  | 'ADR_SUPERSESSION_STATUS'
  | 'ADR_SUPERSESSION_MISSING_SUCCESSOR'
  | 'ADR_SUPERSESSION_ASYMMETRIC'
  | 'ADR_SUPERSEDES_MISSING'
  | 'ADR_SUPERSEDES_ASYMMETRIC'
  | 'STALE_CONTEXT_PACK'
  | 'STALE_INDEX'
  | 'FRONTMATTER_STATUS_CASE';

export type RepairTier = 'auto-fix' | 'needs-approval' | 'report-only';
export type RepairSeverity = 'error' | 'warning';
export type MissingRequiredOwnership = 'generated' | 'templated-user' | 'seeded' | 'report-only';
export type RepairStatus = 'applied' | 'skipped' | 'failed';

export type FindingContext =
  | { code: 'LEGACY_FRONTMATTER_FIELD'; legacyField: string; canonicalField: string }
  | { code: 'INVALID_FRONTMATTER'; field: string; expected: string; actual: string }
  | { code: 'BROKEN_WIKILINK'; target: string; candidates: string[] }
  | { code: 'FORBIDDEN_WIKILINK' }
  | {
      code: 'MISSING_REQUIRED';
      templateName: string;
      areaName: string;
      ownership: MissingRequiredOwnership;
    }
  | { code: 'ADR_NUMBERING_GAP' }
  | { code: 'ADR_NUMBERING_DUPLICATE' }
  | { code: 'ADR_MISSING_SECTION'; section: string }
  | { code: 'ADR_SUPERSESSION_STATUS'; expectedStatus: string; actualStatus: string }
  | { code: 'ADR_SUPERSESSION_MISSING_SUCCESSOR' }
  | { code: 'ADR_SUPERSESSION_ASYMMETRIC' }
  | { code: 'ADR_SUPERSEDES_MISSING' }
  | { code: 'ADR_SUPERSEDES_ASYMMETRIC' }
  | { code: 'STALE_CONTEXT_PACK'; packageScope?: string }
  | { code: 'STALE_INDEX' }
  | { code: 'FRONTMATTER_STATUS_CASE'; actual: string; normalized: string };

export interface RepairableFinding {
  code: FindingCode;
  filePath: string;
  tier: RepairTier;
  severity: RepairSeverity;
  message: string;
  context: FindingContext;
}

export interface RepairResult {
  finding: RepairableFinding;
  status: RepairStatus;
  reason?: string;
  filesModified: string[];
}

export interface ReconcilePlanSummary {
  autoFix: number;
  needsApproval: number;
  reportOnly: number;
}

export interface ReconcilePlan {
  version: string;
  generatedAt: string;
  findings: RepairableFinding[];
  summary: ReconcilePlanSummary;
}

export const FINDING_TIER_ASSIGNMENTS = {
  LEGACY_FRONTMATTER_FIELD: 'auto-fix',
  INVALID_FRONTMATTER: 'report-only',
  BROKEN_WIKILINK: 'report-only',
  FORBIDDEN_WIKILINK: 'report-only',
  MISSING_REQUIRED: 'needs-approval',
  ADR_NUMBERING_GAP: 'report-only',
  ADR_NUMBERING_DUPLICATE: 'report-only',
  ADR_MISSING_SECTION: 'report-only',
  ADR_SUPERSESSION_STATUS: 'auto-fix',
  ADR_SUPERSESSION_MISSING_SUCCESSOR: 'report-only',
  ADR_SUPERSESSION_ASYMMETRIC: 'report-only',
  ADR_SUPERSEDES_MISSING: 'report-only',
  ADR_SUPERSEDES_ASYMMETRIC: 'report-only',
  STALE_CONTEXT_PACK: 'needs-approval',
  STALE_INDEX: 'needs-approval',
  FRONTMATTER_STATUS_CASE: 'auto-fix',
} as const satisfies Record<FindingCode, RepairTier>;

export function resolveRepairTier(context: FindingContext): RepairTier {
  switch (context.code) {
    case 'BROKEN_WIKILINK':
      return context.candidates.length === 1 ? 'auto-fix' : 'report-only';
    case 'MISSING_REQUIRED':
      return context.ownership === 'generated' || context.ownership === 'templated-user'
        ? 'needs-approval'
        : 'report-only';
    default:
      return FINDING_TIER_ASSIGNMENTS[context.code];
  }
}
