import { z } from 'zod';

const hashPattern = /^sha256:[a-f0-9]{64}$/;
const HashString = z.string().regex(hashPattern, 'Must be sha256:<64 hex chars>');
const ScriptPrefix = z
  .string()
  .regex(/^[a-z][a-z0-9-]*$/, 'Must be lowercase alphanumeric with hyphens');

const AreaConfigSchema = z
  .object({
    enabled: z.boolean().default(false),
    scopes: z.array(z.string().min(1)).optional(),
  })
  .passthrough();
export type AreaConfig = z.infer<typeof AreaConfigSchema>;

const GovernanceSchema = z
  .object({
    'sync-check': z.boolean().default(true),
    wikilinks: z.boolean().default(true),
    'adr-governance': z.boolean().default(true),
    'index-build': z.boolean().default(true),
    'intent-check': z.boolean().default(true),
    'enforced-paths': z.array(z.string().min(1)).default([]),
  })
  .default({});

const ScriptsSchema = z
  .object({
    prefix: ScriptPrefix.default('kdoc'),
  })
  .default({ prefix: 'kdoc' });

const PackageConfigSchema = z.object({
  path: z.string().min(1),
  areas: z.record(z.string(), AreaConfigSchema).optional(),
});

const CategoryConfigSchema = z.object({
  label: z.string().min(1),
  template: z.string().optional(),
  description: z.string().optional(),
});

const ExtensionAreaSchema = z.object({
  name: z.string().min(1),
  directory: z.string().min(1),
  templates: z.array(z.string()).optional(),
  required_files: z.array(z.string()).optional(),
  scoped: z.boolean().default(false),
  pack: z.string().optional(),
});
export type ExtensionArea = z.infer<typeof ExtensionAreaSchema>;

export const TopologyEnum = z.enum(['single', 'monorepo', 'vault']);
export type Topology = z.infer<typeof TopologyEnum>;

export const KdocConfigSchema = z
  .object({
    version: z.number().int().positive(),
    root: z.string().min(1).default('Knowledge'),
    packs: z.array(z.string()).default([]),
    tools: z.array(z.string()).default([]),
    areas: z.record(z.string(), AreaConfigSchema).default({}),
    governance: GovernanceSchema,
    scripts: ScriptsSchema,
    topology: TopologyEnum.default('single'),
    packages: z.record(z.string(), PackageConfigSchema).default({}),
    categories: z.record(z.string(), CategoryConfigSchema).optional(),
    extensionAreas: z.array(ExtensionAreaSchema).default([]),
  })
  .passthrough()
  .superRefine((data, ctx) => {
    // packages non-empty only valid when topology is monorepo
    if (Object.keys(data.packages).length > 0 && data.topology !== 'monorepo') {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: 'packages can only be specified when topology is "monorepo"',
        path: ['packages'],
      });
    }
    // categories only valid when topology is vault
    if (data.categories && Object.keys(data.categories).length > 0 && data.topology !== 'vault') {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: 'categories can only be specified when topology is "vault"',
        path: ['categories'],
      });
    }
  });

export type KdocConfig = z.infer<typeof KdocConfigSchema>;

// Lock file entry: discriminated union on "action".
// Note: .refine() returns ZodEffects which cannot be used in z.discriminatedUnion().
// We use a plain union and validate markerName requirement via .refine() on the merged branch.
const CreatedEntrySchema = z.object({
  action: z.literal('created'),
  hash: HashString,
  templateHash: HashString,
  template: z.string().min(1),
});

const MergedEntrySchema = z
  .object({
    action: z.literal('merged'),
    blockHash: HashString,
    templateHash: HashString,
    template: z.string().min(1),
    strategy: z.enum(['markers', 'prefix']),
    markerName: z.string().optional(),
  })
  .refine(
    (data) =>
      data.strategy !== 'markers' || (data.markerName != null && data.markerName.length > 0),
    { message: 'markerName is required when strategy is "markers"', path: ['markerName'] },
  );

export const LockFileEntrySchema = z.union([CreatedEntrySchema, MergedEntrySchema]);

export type LockFileEntry = z.infer<typeof LockFileEntrySchema>;

const LockConfigSchema = z.object({
  root: z.string(),
  packs: z.array(z.string()),
  tools: z.array(z.string()),
  topology: TopologyEnum.optional(),
  packages: z.record(z.string(), z.object({ path: z.string() })).optional(),
});

export const KdocLockSchema = z.object({
  lockVersion: z.number().int().positive(),
  kdocVersion: z.string().min(1),
  installedAt: z.string().datetime(),
  updatedAt: z.string().datetime(),
  config: LockConfigSchema,
  files: z.record(z.string(), LockFileEntrySchema),
});

export type KdocLock = z.infer<typeof KdocLockSchema>;
