/**
 * Explicit mapping table for frontmatter status enum normalization.
 * Canonical values are lowercase. Keys are known non-canonical variants.
 * Returns null when the value is already canonical or unrecognized.
 */

export const STATUS_NORMALIZATION: Record<string, string> = {
  Draft: 'draft',
  DRAFT: 'draft',
  Accepted: 'accepted',
  ACCEPTED: 'accepted',
  Superseded: 'superseded',
  SUPERSEDED: 'superseded',
  Deprecated: 'deprecated',
  DEPRECATED: 'deprecated',
  Proposed: 'proposed',
  PROPOSED: 'proposed',
  Rejected: 'rejected',
  REJECTED: 'rejected',
};

/** Canonical status values that need no normalization. */
export const CANONICAL_STATUSES = new Set([
  'draft',
  'accepted',
  'superseded',
  'deprecated',
  'proposed',
  'rejected',
]);

/**
 * Return the canonical lowercase form if `raw` is a recognized non-canonical variant.
 * Returns `null` when:
 * - `raw` is already canonical (e.g. 'draft')
 * - `raw` is not a recognized status value at all
 */
export function normalizeStatus(raw: string): string | null {
  return STATUS_NORMALIZATION[raw] ?? null;
}
