import { readFileSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';
import type { KdocConfig } from '../../config/schema.js';
import type { RepairableFinding, RepairResult } from '../types.js';

/** Escape special regex characters in a string. */
function escapeForRegex(s: string): string {
  return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

/**
 * Mask inline code spans and fenced code blocks with placeholders so that
 * wikilink replacement only applies to prose content. This mirrors the
 * detection logic in wikilink-resolver.mjs.
 */
function maskCodeSpans(content: string): { masked: string; restore: (s: string) => string } {
  const placeholders: string[] = [];

  // Mask fenced code blocks first (``` ... ```)
  let masked = content.replace(/^```[\s\S]*?^```/gm, (match) => {
    const idx = placeholders.length;
    placeholders.push(match);
    return `\0CODEBLOCK_${idx}\0`;
  });

  // Mask inline code spans (`...`)
  masked = masked.replace(/`[^`]*`/g, (match) => {
    const idx = placeholders.length;
    placeholders.push(match);
    return `\0CODEINLINE_${idx}\0`;
  });

  return {
    masked,
    restore: (s: string) =>
      s.replace(/\0CODE(?:BLOCK|INLINE)_(\d+)\0/g, (_m, idxStr: string) => placeholders[Number(idxStr)]),
  };
}

/**
 * Repair a broken wikilink by rewriting it to the resolved target.
 *
 * AC-14: If the finding has 0 or 2+ candidates, skip with ambiguity reason.
 * Only rewrites when exactly 1 candidate exists.
 *
 * Preserves wikilink aliases: `[[target|display]]` → `[[resolved|display]]`
 * Does NOT rewrite wikilinks inside inline code or fenced code blocks.
 */
export function repairBrokenWikilink(
  finding: RepairableFinding,
  projectDir: string,
  config: KdocConfig,
): RepairResult {
  const ctx = finding.context;
  if (ctx.code !== 'BROKEN_WIKILINK') {
    return { finding, status: 'skipped', reason: 'Wrong context type', filesModified: [] };
  }

  // AC-14: Skip ambiguous wikilinks
  if (ctx.candidates.length === 0) {
    return {
      finding,
      status: 'skipped',
      reason: `No matching targets found for [[${ctx.target}]]`,
      filesModified: [],
    };
  }

  if (ctx.candidates.length > 1) {
    return {
      finding,
      status: 'skipped',
      reason: `Ambiguous: ${ctx.candidates.length} matching targets for [[${ctx.target}]] — ${ctx.candidates.join(', ')}`,
      filesModified: [],
    };
  }

  const resolvedTarget = ctx.candidates[0];

  // Derive the replacement target: strip knowledge root prefix and .md extension
  const knowledgeRoot = config.root ?? 'Knowledge';
  let replacementTarget = resolvedTarget;
  const rootPrefix = `${knowledgeRoot}/`;
  if (replacementTarget.startsWith(rootPrefix)) {
    replacementTarget = replacementTarget.slice(rootPrefix.length);
  }
  replacementTarget = replacementTarget.replace(/\.md$/, '');

  const absPath = join(projectDir, finding.filePath);
  let content: string;
  try {
    content = readFileSync(absPath, 'utf8');
  } catch {
    return { finding, status: 'failed', reason: `Cannot read ${finding.filePath}`, filesModified: [] };
  }

  // Mask code spans before replacement so wikilinks in code are not rewritten
  const { masked, restore } = maskCodeSpans(content);

  const escapedTarget = escapeForRegex(ctx.target);
  const wikilinkPattern = new RegExp(
    `\\[\\[${escapedTarget}((?:\\|[^\\]]*)?\\]\\])`,
    'g',
  );

  const newMasked = masked.replace(wikilinkPattern, `[[${replacementTarget}$1`);
  const newContent = restore(newMasked);

  if (newContent === content) {
    return { finding, status: 'skipped', reason: `Wikilink [[${ctx.target}]] not found in file content`, filesModified: [] };
  }

  writeFileSync(absPath, newContent, 'utf8');
  return { finding, status: 'applied', filesModified: [finding.filePath] };
}
