import { existsSync, readFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { buildScopedRenderValues } from '../../templates/render-values.js';
import { resolveTemplateSource } from '../../templates/catalog.js';
import { renderTemplate } from '../../templates/renderer.js';
import { safeWriteFile } from '../../utils/fs.js';
import type { KdocConfig } from '../../config/schema.js';
import type { RepairResult, RepairableFinding } from '../types.js';
import { buildContextPackArtifact, buildIndexArtifact } from '../artifact-builders.js';

function resolveTemplateContent(
  finding: RepairableFinding,
  projectDir: string,
  config: KdocConfig,
): string {
  const ctx = finding.context;
  if (ctx.code !== 'MISSING_REQUIRED') {
    throw new Error('Invalid missing-file repair context');
  }

  if (ctx.ownership === 'generated') {
    if (finding.filePath.endsWith('/INDEX.md') || finding.filePath === `${config.root ?? 'Knowledge'}/INDEX.md`) {
      return buildIndexArtifact(projectDir, config).content;
    }

    if (finding.filePath.endsWith('/ContextPack.md')) {
      const match = finding.filePath.match(/\/packages\/([^/]+)\/ContextPack\.md$/);
      return buildContextPackArtifact(projectDir, config, match?.[1]).content;
    }
  }

  const template = resolveTemplateSource(ctx.templateName);
  if (!template) {
    throw new Error(`Template not found: ${ctx.templateName}`);
  }

  const scopePath = dirname(finding.filePath).endsWith('/ADR') ||
    dirname(finding.filePath).endsWith('/TLDR') ||
    dirname(finding.filePath).endsWith('/Design') ||
    dirname(finding.filePath).endsWith('/Roadmap')
    ? dirname(dirname(finding.filePath))
    : dirname(finding.filePath);

  return renderTemplate(
    template.content,
    buildScopedRenderValues(config, projectDir, scopePath === '.' ? undefined : scopePath),
  ).content;
}

export function repairMissingRequired(
  finding: RepairableFinding,
  projectDir: string,
  config: KdocConfig,
): RepairResult {
  const ctx = finding.context;
  if (ctx.code !== 'MISSING_REQUIRED') {
    return { finding, status: 'skipped', reason: 'Wrong context type', filesModified: [] };
  }

  if (ctx.ownership === 'seeded' || ctx.ownership === 'report-only') {
    return {
      finding,
      status: 'skipped',
      reason: `${ctx.ownership} files require manual authorship`,
      filesModified: [],
    };
  }

  const targetPath = join(projectDir, finding.filePath);
  const content = resolveTemplateContent(finding, projectDir, config);

  if (existsSync(targetPath)) {
    const existing = readFileSync(targetPath, 'utf8');
    if (existing === content) {
      return {
        finding,
        status: 'skipped',
        reason: 'file already matches the expected content',
        filesModified: [],
      };
    }
  }

  safeWriteFile(targetPath, content);
  return { finding, status: 'applied', filesModified: [finding.filePath] };
}
